// 입력값의 HTML 태그를 무력화하여 XSS 공격을 방어하는 유틸리티 함수
function escapeHTML(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}
function switchView(v) {
  curView = v;
  document.getElementById('viewHome').classList.toggle('active', v==='home');
  document.getElementById('viewAdmin').classList.toggle('active', v==='admin');
  if(v==='home') {
    homeScreen = 'A';
    renderHomeA();
  }
  if(v==='admin') {
    // 관리자 모드 진입 시 항상 첫 번째 카테고리(농산>전체보기)로 초기화
    aState = {cat:MAIN_CATS[0], sub:'', prod:'__all__', search:''};
    adminTab = 'archive';
    renderAdmin();
  }
  savePageState();
}

