function homeGoBack() {
  curView = 'home';
  homeScreen='A';
  hState = {cat:'', sub:'', prod:'__all__', search:''};
  try { sessionStorage.removeItem('pageState'); } catch(e) {}
  savePageState();
  renderHomeA();
}
function homeSubSelect(sub) {
  hState.sub=sub;
  hState.prod='__all__';
  hState.search='';
  savePageState();
  renderHomeB();
}
function homeSearchChange(val) {
  hState.search = val;
  savePageState();
  var clearBtn = document.getElementById('homeSearchClear');
  if(clearBtn) clearBtn.classList.toggle('visible', !!val);
  renderHomeContent();
}

function renderHomeContent() {
  const el = document.getElementById('homeContent');
  if(!el) return;
  const searchQ = (hState.search||'').trim().toLowerCase();

  if(searchQ) {
    // 검색 모드: sub 전체보기면 전체 sub 검색, 아니면 해당 sub만
    const searchProds = hState.sub
      ? getProds(hState.cat, hState.sub)
      : getSubs(hState.cat).flatMap(s => getProds(hState.cat, s.name));
    let allAds = [];
    searchProds.forEach(function(p) {
      getAds(hState.cat, p.subCat||hState.sub, p.name).forEach(function(ad) { allAds.push(ad); });
    });
    const filtered = allAds.filter(function(ad) {
      return ad.title.toLowerCase().includes(searchQ)
        || (ad.product||'').toLowerCase().includes(searchQ);
    });
    if(filtered.length === 0) {
      el.innerHTML = `<div class="kempty">
        <svg viewBox="0 0 48 48" fill="none" stroke="#ccc" stroke-width="1.5" width="40" height="40" style="margin:0 auto 12px;display:block;"><circle cx="22" cy="22" r="16"/><line x1="34" y1="34" x2="44" y2="44"/></svg>
        <div class="kempty-title">"${hState.search}"에 대한 결과가 없습니다</div>
        <div class="kempty-sub">다른 검색어를 입력해보세요</div>
      </div>`;
    } else {
      el.innerHTML = `<div style="font-size:13px;font-weight:600;color:#999;margin-bottom:16px;">${filtered.length}개의 광고</div>
        <div class="kad-grid">${filtered.map(ad=>adCardHTML(ad,'home')).join('')}</div>`;
    }
    return;
  }

  // 검색 없음: 전체보기면 전체 sub 순회, 아니면 해당 sub만
  const prods = hState.sub
    ? getProds(hState.cat, hState.sub)
    : getSubs(hState.cat).flatMap(s => getProds(hState.cat, s.name));
  const withAds = prods.filter(p=>getAds(hState.cat, p.subCat||hState.sub, p.name).length>0);
  if(withAds.length===0) {
    el.innerHTML=`<div class="kempty"><div class="kempty-title">등록된 광고가 없습니다</div><div class="kempty-sub">관리자 모드에서 이미지를 등록하세요</div></div>`;
  } else {
    el.innerHTML = withAds.map(p=>{
      const ads=getAds(hState.cat, p.subCat||hState.sub, p.name);
      const subLabel = !hState.sub ? `<span style="font-size:12px;color:#aaa;font-weight:500;margin-left:6px;">${p.subCat}</span>` : '';
      return `<div style="margin-bottom:36px;">
        <div class="ksect-title">${p.name}${subLabel}</div>
        <div class="kad-grid">${ads.map(ad=>adCardHTML(ad,'home')).join('')}</div>
      </div>`;
    }).join('');
  }
}

function adCardHTML(ad, mode) {
  const srcs = (ad.types||[]).map(t=>t.src).filter(Boolean);
  const thumb = srcs[0] || '';
  const total = srcs.length;
  const overlayBtns = mode==='admin' ? `
    <button class="kad-ov-btn" onclick="event.stopPropagation();openLightbox('${thumb}')">
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><path d="M15 3h6v6M9 21H3v-6M21 3l-7 7M3 21l7-7"/></svg>
    </button>
    <button class="kad-ov-btn" onclick="event.stopPropagation();openEditImg(${ad.id})">
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
    </button>
    <button class="kad-ov-btn del" onclick="event.stopPropagation();deleteAd(${ad.id})">
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><polyline points="3,6 5,6 21,6"/><path d="M19 6l-1 14H6L5 6"/></svg>
    </button>
  ` : '';

  var thumbInner = '';
  if(!thumb) {
    thumbInner = `<div class="kad-thumb-empty">
      <svg viewBox="0 0 48 48" fill="none" stroke="currentColor" stroke-width="1.5" width="32" height="32" style="opacity:.3"><rect x="6" y="14" width="36" height="26" rx="4"/><circle cx="18" cy="26" r="4"/><path d="m6 36 10-8 8 8 6-6 12 10"/></svg>
      <span>이미지 없음</span>
    </div>`;
  } else if(total <= 1) {
    thumbInner = `<img src="${thumb}" alt="${escapeHTML(ad.title)}" />`;
  } else {
    var uid = 'cs_' + ad.id;
    var slides = srcs.map(function(src) {
      return `<div class="kcard-slide" style="flex:0 0 100%;width:100%;"><img src="${src}" style="width:100%;height:100%;object-fit:cover;" /></div>`;
    }).join('');
    var dots = srcs.map(function(_, i) {
      return `<span class="kcard-dot ${i===0?'active':''}" onclick="event.stopPropagation();cardSlide('${uid}',${i})"></span>`;
    }).join('');
    thumbInner = `
      <div class="kcard-slider" id="${uid}" data-idx="0">
        <div class="kcard-slides" style="display:flex;width:100%;height:100%;transition:transform .25s ease;">
          ${slides}
        </div>
        <button class="kcard-arrow kcard-arrow-l" onclick="event.stopPropagation();cardSlide('${uid}',-1,true)">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" width="14" height="14"><polyline points="15 18 9 12 15 6"/></svg>
        </button>
        <button class="kcard-arrow kcard-arrow-r" onclick="event.stopPropagation();cardSlide('${uid}',1,true)">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" width="14" height="14"><polyline points="9 6 15 12 9 18"/></svg>
        </button>
        <div class="kcard-dots" id="${uid}_dots">${dots}</div>
      </div>`;
  }

  return `
    <div class="kad-card" onclick="openDetail(${ad.id}, '${mode}')">
      <div class="kad-thumb-wrap">
        <div class="kad-thumb">
          ${thumbInner}
          <div class="kad-overlay">${overlayBtns}</div>
        </div>
      </div>
      <div class="kad-meta">
        <div class="kad-tag">${escapeHTML(ad.subCat)}</div>
        <div class="kad-title">${escapeHTML(ad.title)}</div>
        <div class="kad-date">등록일: ${escapeHTML(ad.adDate)}</div>
      </div>
    </div>
  `;
}

function cardSlide(uid, val, isRelative) {
  var el = document.getElementById(uid);
  if(!el) return;
  var total = el.querySelectorAll('.kcard-slide').length;
  var cur = parseInt(el.dataset.idx) || 0;
  var next = isRelative ? cur + val : val;
  if(next < 0) next = total - 1;
  if(next >= total) next = 0;
  el.dataset.idx = next;
  var slides = el.querySelector('.kcard-slides');
  if(slides) slides.style.transform = 'translateX(-' + (next * 100) + '%)';
  var dotsEl = document.getElementById(uid + '_dots');
  if(dotsEl) dotsEl.querySelectorAll('.kcard-dot').forEach(function(d, i) {
    d.classList.toggle('active', i === next);
  });
}

