function adminGoNormal() {
  hState = {cat:aState.cat, sub:aState.sub, prod:'__all__', search:''};
  curView = 'home';
  homeScreen = 'B';
  document.getElementById('viewHome').classList.add('active');
  document.getElementById('viewAdmin').classList.remove('active');
  savePageState();
  renderHomeB();
}

// ── 탭을 가로 스크롤 중앙으로 부드럽게 이동 (깜빡임 없이) ──
function _scrollTabIntoCenter(cat, barId, behavior) {
  var tabBar = barId ? document.getElementById(barId) : document.querySelector('.ktab-bar');
  if(!tabBar) return;
  var btns = tabBar.querySelectorAll('.ktab-btn');
  var idx = MAIN_CATS.indexOf(cat);
  if(idx < 0 || !btns[idx]) return;
  var btn = btns[idx];
  var target = btn.offsetLeft - (tabBar.offsetWidth / 2) + (btn.offsetWidth / 2);
  tabBar.scrollTo({left: Math.max(0, target), behavior: behavior || 'smooth'});
}

function adminCatSelect(cat) {
  aState = {cat, sub:'', prod:'__all__', search:''};
  savePageState();

  // 탭바가 DOM에 이미 있으면 active만 교체 후 스크롤 (깜빡임 없음)
  var catBar = document.getElementById('adminCatBar');
  if(catBar) {
    var btns = catBar.querySelectorAll('.ktab-btn');
    btns.forEach(function(btn, i) {
      btn.classList.toggle('active', MAIN_CATS[i] === cat);
    });
    _scrollTabIntoCenter(cat, 'adminCatBar');
    // 콘텐츠(서브바 + 상품바 + 그리드)만 갱신
    renderAdminContent();
    // 서브 바도 갱신
    var subScroll = document.getElementById('adminSubScroll');
    if(subScroll) {
      var subs2 = getSubs(cat);
      var html = '<button class="ksub-pill active" onclick="adminSubSelect(\'\')">전체보기</button>';
      subs2.forEach(function(s) {
        html += '<div style="display:flex;align-items:center;gap:2px;flex-shrink:0;">'
          + '<button class="ksub-pill" data-id="'+s.id+'" onclick="adminSubSelect(\''+s.name+'\')">'+s.name+'</button>'
          + '<button class="ksub-pill-del" title="'+s.name+' 삭제" onclick="adminDeleteSub('+s.id+',\''+s.name+'\')">×</button>'
          + '</div>';
      });
      subScroll.innerHTML = html;
    }
  } else {
    // 탭바 없으면 전체 렌더 후 스크롤
    renderAdmin();
    setTimeout(function(){ _scrollTabIntoCenter(cat, 'adminCatBar'); }, 60);
  }
}
function adminSubSelect(sub) { aState.sub=sub; aState.prod='__all__'; aState.search=''; savePageState(); renderAdmin(); }
function adminSearchChange(val) {
  aState.search = val;
  var clearBtn = document.getElementById('adminSearchClear');
  if(clearBtn) clearBtn.classList.toggle('visible', !!val);
  renderAdminContent();
}

function renderAdminContent() {
  ['adminSubRow','adminCatBar','adminSearchRow'].forEach(function(id){
    var el=document.getElementById(id);
    if(el) el.style.display='';
  });
  var searchRow = document.getElementById('adminSearchRow');
  if(searchRow) searchRow.style.display='flex';

  const el = document.getElementById('adminContent');
  if(!el) return;
  const searchQ = (aState.search||'').trim().toLowerCase();

  if(searchQ) {
    const searchProds = aState.sub
      ? getProds(aState.cat, aState.sub)
      : getSubs(aState.cat).flatMap(s => getProds(aState.cat, s.name));
    let allAds = [];
    searchProds.forEach(function(p){ getAds(aState.cat, p.subCat||aState.sub, p.name).forEach(function(ad){ allAds.push(ad); }); });
    const filtered = allAds.filter(function(ad){
      return ad.title.toLowerCase().includes(searchQ) || (ad.product||'').toLowerCase().includes(searchQ);
    });
    if(filtered.length === 0) {
      el.innerHTML = `<div class="kempty">
        <svg viewBox="0 0 48 48" fill="none" stroke="#ccc" stroke-width="1.5" width="40" height="40" style="margin:0 auto 12px;display:block;"><circle cx="22" cy="22" r="16"/><line x1="34" y1="34" x2="44" y2="44"/></svg>
        <div class="kempty-title">"${aState.search}"에 대한 결과가 없습니다</div>
        <div class="kempty-sub">다른 검색어를 입력해보세요</div>
      </div>`;
    } else {
      el.innerHTML = `<div style="font-size:13px;font-weight:600;color:#999;margin-bottom:16px;">${filtered.length}개의 광고</div>
        <div class="kad-grid">${filtered.map(ad=>adCardHTML(ad,'admin')).join('')}</div>`;
    }
    return;
  }

  // 검색 없음: 상품별 섹션으로 표시
  const prods = aState.sub
    ? getProds(aState.cat, aState.sub)
    : getSubs(aState.cat).flatMap(s => getProds(aState.cat, s.name));
  if(prods.length===0) {
    el.innerHTML=`<div class="kempty"><div class="kempty-title">등록된 상품이 없습니다</div></div>`;
  } else {
    el.innerHTML = prods.map(p=>{
      const ads = getAds(aState.cat, p.subCat||aState.sub, p.name);
      const gridOrEmpty = ads.length > 0
        ? '<div class="kad-grid">' + ads.map(ad=>adCardHTML(ad,'admin')).join('') + '</div>'
        : emptyAdMsg();
      const subLabel = !aState.sub ? `<span style="font-size:12px;color:#aaa;font-weight:500;margin-left:6px;">${p.subCat}</span>` : '';
      return `<div style="margin-bottom:36px;padding-bottom:36px;border-bottom:1px solid rgba(0,0,0,0.06);">
        <div class="ksect-title">
          ${p.name}${subLabel}
          <button class="ksect-add-btn" onclick="openAddImg('${p.name}')">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" width="16" height="16"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
          </button>
        </div>
        ${gridOrEmpty}
      </div>`;
    }).join('');
  }
}

