function _resetModalScroll(el) {
  // display:flex/.open 상태에서만 scrollTop 리셋 가능하므로 직접 지정
  ['.kmodal-sheet', '.kdetail-modal', '#detailContent', '#rq-scroll-area', '#adreq-scroll-area'].forEach(function(sel) {
    el.querySelectorAll(sel).forEach(function(node) { node.scrollTop = 0; });
  });
  el.scrollTop = 0;
}
function modalClose(id) {
  const el = document.getElementById(id);
  if(!el) return;
  el.classList.remove('open');
  // 닫힌 뒤 스크롤 리셋 (다음에 열릴 때 최상단 보장)
  setTimeout(function(){ _resetModalScroll(el); }, 0);
}
function modalOpen(id) {
  const el = document.getElementById(id);
  if(!el) return;
  el.classList.add('open');
  // open → display:flex 된 직후 리셋
  requestAnimationFrame(function(){
    _resetModalScroll(el);
  });
}

// close on overlay click
document.querySelectorAll('.kmodal-overlay').forEach(el=>{
  if(el.id === 'modalRequest') return;
  if(el.id === 'modalAddImg') return;
  if(el.id === 'modalEditCat') return;
  if(el.id === 'modalAdRequest') return;
  if(el.id === 'modalCatMgr') return;
  el.addEventListener('click', e=>{
    if(e.target===el && !el._blockClose) {
      _resetModalScroll(el);
      el.classList.remove('open');
    }
  });
});

// ── 모든 모달 스와이프-다운 닫기 (모바일) ──
(function() {
  // 닫으면 안 되는 모달 제외 없이 전체 적용 (편집 탭은 _blockClose로 방지)
  var SWIPE_THRESHOLD = 80; // px — 이 이상 내리면 닫힘

  function addSwipeClose(overlay) {
    var sheet = overlay.querySelector('.kmodal-sheet, .kdetail-modal');
    if(!sheet) return;

    var startY = 0, currentY = 0, isDragging = false;

    function getScrollTop() {
      // 내부 스크롤 가능한 영역의 scrollTop
      var scrollable = sheet.querySelector('#rq-scroll-area, #adreq-scroll-area, #catmgr-scroll-area') || sheet;
      return scrollable.scrollTop;
    }

    sheet.addEventListener('touchstart', function(e) {
      // 내부가 최상단일 때만 스와이프 감지
      if(getScrollTop() > 4) return;
      if(overlay._blockClose) return;
      startY = e.touches[0].clientY;
      currentY = startY;
      isDragging = true;
      sheet.style.transition = 'none';
    }, {passive: true});

    sheet.addEventListener('touchmove', function(e) {
      if(!isDragging) return;
      currentY = e.touches[0].clientY;
      var dy = currentY - startY;
      if(dy > 0) {
        sheet.style.transform = 'translateY(' + dy + 'px)';
      }
    }, {passive: true});

    sheet.addEventListener('touchend', function(e) {
      if(!isDragging) return;
      isDragging = false;
      var dy = currentY - startY;
      sheet.style.transition = '';
      sheet.style.transform = '';
      if(dy > SWIPE_THRESHOLD && !overlay._blockClose) {
        _resetModalScroll(overlay);
        overlay.classList.remove('open');
      }
    }, {passive: true});
  }

  // DOM 로드 후 모든 overlay에 적용
  document.querySelectorAll('.kmodal-overlay').forEach(function(overlay) {
    addSwipeClose(overlay);
  });

  // 동적으로 생성되는 모달(modalReqUserDetail 등)도 감지
  var observer = new MutationObserver(function(mutations) {
    mutations.forEach(function(m) {
      m.addedNodes.forEach(function(node) {
        if(node.classList && node.classList.contains('kmodal-overlay')) {
          addSwipeClose(node);
        }
      });
    });
  });
  observer.observe(document.body, {childList: true});
})();

