// 셋팅 사진 관련
var editSettingPhotos = null; // null = 변경 없음, array = 변경됨

function editAddSettingPhotos(input) {
  var files = Array.from(input.files);
  if(!files.length) return;
  var current = editSettingPhotos !== null ? editSettingPhotos : (detailAd.settingPhotos||[]).map(function(p){ return typeof p==='object' ? p : {src:p, storeName:''}; });
  var preview = document.getElementById('editSettingPreview');
  files.forEach(function(file) {
    var reader = new FileReader();
    reader.onload = function(e) {
      var newItem = {src: e.target.result, storeName: ''};
      current.push(newItem);
      editSettingPhotos = current;
      var i = current.length - 1;
      var div = document.createElement('div');
      div.id = 'editSettingItem_' + i;
      div.style.cssText = 'border:1.5px solid rgba(0,0,0,0.1);border-radius:6px;overflow:hidden;';
      div.innerHTML = `<img src="${e.target.result}" style="width:100%;max-height:200px;object-fit:cover;display:block;" />
        <div style="display:flex;align-items:center;gap:8px;padding:8px 10px;background:#f2f2f2;">
          <input class="kinput" type="text" id="editSettingStore_${i}" placeholder="매장명 (예: 강서점)" style="flex:1;font-size:13px;" />
          <button onclick="editRemoveSettingPhoto(${i})" style="padding:5px 12px;background:#ffe0e0;border:none;border-radius:6px;color:#e03333;font-size:12px;font-weight:700;cursor:pointer;white-space:nowrap;">삭제</button>
        </div>`;
      if(preview) preview.appendChild(div);
    };
    reader.readAsDataURL(file);
  });
  input.value = '';
}

function editRemoveSettingPhoto(idx) {
  var current = editSettingPhotos !== null ? editSettingPhotos : (detailAd.settingPhotos||[]).map(function(p){ return typeof p==='object' ? p : {src:p, storeName:''}; });
  current.splice(idx, 1);
  editSettingPhotos = current;
  var preview = document.getElementById('editSettingPreview');
  if(preview) {
    preview.innerHTML = current.map(function(p, i) {
      var src = typeof p === 'object' ? (p.src||'') : p;
      var storeName = typeof p === 'object' ? (p.storeName||'') : '';
      return `<div style="border:1.5px solid rgba(0,0,0,0.1);border-radius:6px;overflow:hidden;">
        <img src="${src}" style="width:100%;max-height:200px;object-fit:cover;display:block;" />
        <div style="display:flex;align-items:center;gap:8px;padding:8px 10px;background:#f2f2f2;">
          <input class="kinput" type="text" id="editSettingStore_${i}" value="${storeName.replace(/"/g,'&quot;')}" placeholder="매장명 (예: 강서점)" style="flex:1;font-size:13px;" />
          <button onclick="editRemoveSettingPhoto(${i})" style="padding:5px 12px;background:#ffe0e0;border:none;border-radius:6px;color:#e03333;font-size:12px;font-weight:700;cursor:pointer;white-space:nowrap;">삭제</button>
        </div>
      </div>`;
    }).join('');
  }
}

function editSave() {
  const title=document.getElementById('editTitle')?.value.trim();
  if(!title){alert('광고 이름을 입력하세요');return;}
  const newCat  = document.getElementById('editCat')?.value || detailAd.mainCat;
  const newSub  = document.getElementById('editSubSel')?.value || detailAd.subCat;
  const newProd = document.getElementById('editProdSel')?.value || detailAd.product;

  const blocks=document.querySelectorAll('[id^="editTypeBlock_"]');
  const rawTypes=Array.from(blocks).map(b=>{
    const idx=parseInt(b.id.replace('editTypeBlock_',''));
    const sel=b.querySelector('select');
    const name=sel.value==='__custom__'?(document.getElementById(`editTypeCustomName_${idx}`)?.value.trim()||'기타'):sel.value;
    const width=document.getElementById(`editTypeW_${idx}`)?.value.trim()||'';
    const height=document.getElementById(`editTypeH_${idx}`)?.value.trim()||'';
    const subtitle=document.getElementById(`editTypeSubtitle_${idx}`)?.value.trim()||'';
    const memo=document.getElementById(`editTypeMemo_${idx}`)?.value.trim()||'';
    const unitPrice=document.getElementById(`editTypePrice_${idx}`)?.value.trim()||'';
    const newSrc=editTypeSrcs[idx];
    const origType=(detailAd.types||[])[idx];
    const origSrc=origType?.src||'';
    const src=newSrc!==null&&newSrc!==undefined?newSrc:origSrc;
    return {name,subtitle,width,height,src,memo,unitPrice};
  });

  const memo=document.getElementById('editMemo')?.value.trim()||'';
  const idx=DB.ads.findIndex(a=>a.id===detailAd.id);
  if(idx===-1)return;
  const settingPhotos = (editSettingPhotos !== null ? editSettingPhotos : (detailAd.settingPhotos||[])).map(function(p, i) {
    var src = typeof p === 'object' ? (p.src||'') : p;
    var storeEl = document.getElementById('editSettingStore_' + i);
    var storeName = storeEl ? storeEl.value.trim() : (typeof p === 'object' ? (p.storeName||'') : '');
    return {src, storeName};
  });
  editSettingPhotos = null;

  // base64 이미지는 Storage에 업로드 후 저장
  processAdTypes(rawTypes).then(async function(finalTypes) {
    // 셋팅 사진 Storage 업로드 (src만 업로드, storeName 유지)
    const finalSettingPhotos = [];
    for(var si=0; si<settingPhotos.length; si++) {
      var sp = settingPhotos[si];
      var spSrc = typeof sp === 'object' ? (sp.src||'') : sp;
      var spStore = typeof sp === 'object' ? (sp.storeName||'') : '';
      if(spSrc && spSrc.startsWith('data:')) {
        var uploadedUrl = await uploadImageToStorage(spSrc, 'setting_' + si);
        finalSettingPhotos.push({src: uploadedUrl || spSrc, storeName: spStore});
      } else {
        finalSettingPhotos.push({src: spSrc, storeName: spStore});
      }
    }
    DB.ads[idx]={...DB.ads[idx],mainCat:newCat,subCat:newSub,product:newProd,title,memo:'',types:finalTypes,adDate:new Date().toLocaleDateString('ko-KR'),settingPhotos:finalSettingPhotos};
    detailAd=DB.ads[idx];
    saveData();
    sbUpdateAd(DB.ads[idx]);
    detailTab='view';
    renderDetail();
    renderAdmin();
    if(homeScreen==='B') renderHomeContent();
  });
}

function openEditImg(id) {
  // open detail modal on edit tab directly - id 타입 통일
  detailAd=DB.ads.find(a=>String(a.id)===String(id));
  if(!detailAd)return;
  detailTab='edit';
  renderDetail();
  modalOpen('modalDetail');
}

