  var calCusEl = document.getElementById('rq-custom-calendar'); if(calCusEl) calCusEl.value='';
  if(rqFixedPicker){ rqFixedPicker.destroy(); rqFixedPicker=null; }
  if(rqCustomPicker){ rqCustomPicker.destroy(); rqCustomPicker=null; }
  rqDeliveryTab='fixed';
  // 탭 초기 상태
