// 사이즈 카드가 나오는 항목 (A3/A4는 사이즈 없이 수량만)
var RQ_SIZE_ITEMS = ['중분류','시트','배너','우드락 셀링','디바이더','평대자석','등신대','현수막','기타','와블러','A3 가로형','A4 세로형'];

function rqToggleItem(el, cat) {
  var val = el.dataset.val;
  var key = cat+'::'+val;
  var isSelected = el.classList.contains('selected');

  if(isSelected) {
    el.classList.remove('selected');
    rqSelectedTypes.delete(key);
  } else {
    el.classList.add('selected');
    rqSelectedTypes.add(key);
  }

  // 기타 직접 입력란 (연출물 기타)
  if(val === '기타' && cat === '연출물') {
    var ci = document.getElementById('rq-custom-type-input');
    if(ci) ci.style.display = isSelected ? 'none' : '';
  }

  // 배지 업데이트
  var catCount = Array.from(rqSelectedTypes).filter(function(k){ return k.startsWith(cat+'::'); }).length;
  var badge = document.getElementById('rqbadge-'+cat);
  if(badge) { badge.textContent = catCount||''; badge.classList.toggle('visible', catCount>0); }

  // 드롭다운 닫기 (기타 직접입력 항목은 입력란이 드롭다운 안이라 유지)
  if(!(val === '기타' && cat === '연출물')) {
    var tab = document.getElementById('rqtab-'+cat);
    var body = document.getElementById('rqbody-'+cat);
    if(tab) tab.classList.remove('open');
    if(body) body.style.display = 'none';
  }

  renderAdTypeDetails();
  rqUpdateConditionalSections();
}

function renderAdTypeDetails() {
  var container = document.getElementById('rq-adtype-details');
  if(!container) return;

  // 사이즈/수량 입력이 필요한 선택 항목만 카드로 렌더
  var sizeItems = Array.from(rqSelectedTypes).map(function(k){ return k.split('::')[1]||k; })
    .filter(function(v){ return RQ_SIZE_ITEMS.indexOf(v) !== -1; });

  if(sizeItems.length === 0) {
    container.innerHTML = '';
    return;
  }

  container.innerHTML = '<div style="margin-top:12px;display:flex;flex-direction:column;gap:8px;">'
    + sizeItems.map(function(label) {
        var safeLabel = label.replace(/\s/g,'_');
        var isQtyOnly = label === 'A3 가로형' || label === 'A4 세로형';
        var sizeBlock = !isQtyOnly
          ? '<input class="kinput" type="number" placeholder="가로" id="rq-w-'+safeLabel+'" style="flex:1;min-width:60px;" />'
            + '<span style="font-size:15px;color:#bbb;font-weight:400;flex-shrink:0;">×</span>'
            + '<input class="kinput" type="number" placeholder="세로" id="rq-h-'+safeLabel+'" style="flex:1;min-width:60px;" />'
            + '<span style="font-size:13px;color:#888;font-weight:500;flex-shrink:0;white-space:nowrap;">mm</span>'
            + '<span style="width:1px;height:22px;background:#d8dce3;flex-shrink:0;margin:0 2px;"></span>'
          : '';
        var origKey = Array.from(rqSelectedTypes).find(function(k){ return k.split('::')[1]===label; });
        return '<div style="position:relative;background:#f2f2f2;border-radius:6px;padding:14px 16px;">'
          + '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;">'
          + '<span style="font-size:12px;font-weight:700;color:#4a7cf4;letter-spacing:-0.01em;">'+label+'</span>'
          + '<button type="button" onclick="rqRemoveItem(\''+( origKey||('?::'+label) )+'\')" style="width:20px;height:20px;border-radius:50%;background:rgba(74,124,244,0.12);border:none;cursor:pointer;font-size:14px;line-height:1;color:#4a7cf4;flex-shrink:0;">×</button>'
          + '</div>'
          + '<div style="display:flex;align-items:center;gap:8px;">'
          + sizeBlock
          + '<input class="kinput" type="number" placeholder="수량" id="rq-qty-'+safeLabel+'" min="1" style="'+(isQtyOnly?'flex:1;':'width:72px;flex-shrink:0;')+'" />'
          + '<span style="font-size:13px;color:#888;font-weight:500;flex-shrink:0;">개</span>'
          + '</div>'
          + '</div>';
      }).join('')
    + '</div>';
}



function rqRemoveItem(key) {
  // key: "카테고리::값" 형태
  var cat = key.split('::')[0];
  var val = key.split('::').slice(1).join('::');
  rqSelectedTypes.delete(key);
  // 드롭다운 selected 상태 해제
  var bodyEl = document.getElementById('rqbody-'+cat);
  if(bodyEl) {
    var items = bodyEl.querySelectorAll('.rq-adcat-item');
    items.forEach(function(el){ if(el.dataset.val===val) el.classList.remove('selected'); });
  }
  // 기타 입력란 숨기기
  if(val==='기타' && cat==='연출물') {
    var ci = document.getElementById('rq-custom-type-input');
    if(ci) ci.style.display = 'none';
  }
  // 배지 업데이트
  var catCount = Array.from(rqSelectedTypes).filter(function(k){ return k.startsWith(cat+'::'); }).length;
  var badge = document.getElementById('rqbadge-'+cat);
  if(badge) { badge.textContent = catCount||''; badge.classList.toggle('visible', catCount>0); }
  // 탭 상태 업데이트
  var tab = document.getElementById('rqtab-'+cat);
  if(tab && catCount===0) tab.classList.remove('open');
  renderAdTypeDetails();
  rqUpdateConditionalSections();
}
let rqProductFiles = [];

function rqHandleFiles(input, type) {
  const files = Array.from(input.files);
  const previewEl = document.getElementById(`rq-${type}-preview`);
  files.forEach(file => {
    if(type === 'site') rqSiteFiles.push(file);
    else if(type === 'product') rqProductFiles.push(file);
    else rqRefFiles.push(file);
    const reader = new FileReader();
    reader.onload = e => {
      const isPdf = file.type === 'application/pdf';
      const div = document.createElement('div');
      div.style.cssText = 'position:relative;width:80px;height:80px;border-radius:6px;overflow:hidden;border:1px solid rgba(0,0,0,0.1);flex-shrink:0;background:#f2f2f2;display:flex;align-items:center;justify-content:center;';
      div.innerHTML = isPdf
        ? `<div style="font-size:10px;font-weight:700;color:#555;text-align:center;padding:4px;">${file.name.slice(0,15)}...</div>`
        : `<img src="${e.target.result}" style="width:100%;height:100%;object-fit:cover;" />`;
      // delete button
      const del = document.createElement('button');
      del.innerHTML = '×';
      del.style.cssText = 'position:absolute;top:2px;right:2px;width:18px;height:18px;border-radius:50%;background:rgba(0,0,0,0.6);color:#fff;border:none;cursor:pointer;font-size:12px;line-height:1;display:flex;align-items:center;justify-content:center;';
      del.onclick = () => {
        if(type==='site') rqSiteFiles = rqSiteFiles.filter(f=>f!==file);
        else if(type==='product') rqProductFiles = rqProductFiles.filter(f=>f!==file);
        else rqRefFiles = rqRefFiles.filter(f=>f!==file);
        div.remove();
      };
      div.appendChild(del);
      previewEl.appendChild(div);
    };
    reader.readAsDataURL(file);
  });
  input.value = '';
}

function rqSubmit() {
  // 수정 모드인 경우
  if(rqEditTargetId) {
    rqEditSave();
    return;
  }
  const dept = document.getElementById('rq-dept').value.trim();
  const name = document.getElementById('rq-name').value.trim();
  const tel = document.getElementById('rq-tel').value.trim();

  const title = document.getElementById('rq-title').value.trim();
  const deadline = document.getElementById('rq-deadline').value;

  // 광고 종류: key에서 값만 추출
  var adTypesArr = Array.from(rqSelectedTypes).map(function(k){ return k.split('::')[1]||k; });
  var customTypeText = (document.getElementById('rq-custom-type-text')?.value||'').trim();
  if(adTypesArr.includes('직접 작성') && customTypeText) {
    adTypesArr = adTypesArr.map(function(v){ return v==='직접 작성'?customTypeText:v; });
  }

  var hasPOP = Array.from(rqSelectedTypes).some(function(k){ return k.startsWith('POP::'); });
  var has연출물 = Array.from(rqSelectedTypes).some(function(k){ return k.startsWith('연출물::'); });

  // 입고 관련 (연출물 선택 시만)
  var branch = '';
  var deliveryDay = '';
  var deliveryDate = '';
  if(has연출물) {
    branch = (document.getElementById('rq-branch')?.value||'').trim();
    deliveryDay = (document.getElementById('rq-delivery-day')?.value||'').trim();
    if(deliveryDay === '별도지정일') {
      deliveryDate = (document.getElementById('rq-custom-date')?.value||'').trim();
    } else {
      deliveryDate = (document.getElementById('rq-delivery-date')?.value||'').trim();
    }
  }

  var adTitle = document.getElementById('rq-ad-title').value.trim();
  var selling = document.getElementById('rq-selling').value.trim();

  var missing = [];
  if(!dept || !name || !tel) missing.push('요청자 정보');
  if(rqSelectedTypes.size === 0) missing.push('광고 종류');
  if(has연출물) {
    if(!branch) missing.push('입고 지점');
    if(!deliveryDate) missing.push('입고일 날짜');
    // 수정 모드: 기존 사진(DOM img) 또는 새 파일 있으면 OK
    var siteImgCount = (document.getElementById('rq-site-preview')?.querySelectorAll('img')||[]).length;
    if(rqSiteFiles.length === 0 && siteImgCount === 0) missing.push('현장 사진');
  }
  if(hasPOP) {
    var prodImgCount = (document.getElementById('rq-product-preview')?.querySelectorAll('img')||[]).length;
    if(rqProductFiles.length === 0 && prodImgCount === 0) missing.push('상품 사진');
  }
  if(!title) missing.push('요청 제목');
  if(!deadline) missing.push('마감 요청일');
  if(!adTitle) missing.push('타이틀');
  if(!selling) missing.push('셀링 문구');

  if(missing.length > 0) {
    var toast = document.createElement('div');
    toast.style.cssText = 'position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);background:#fff;border:1.5px solid #e03333;color:#e03333;padding:20px 28px;border-radius:10px;font-size:14px;font-weight:700;z-index:9999;box-shadow:0 8px 32px rgba(0,0,0,0.15);text-align:center;line-height:1.6;animation:toastIn .2s ease;';
    toast.innerHTML = '<div style="font-size:16px;margin-bottom:6px;">필수 항목을 작성해주세요</div><div style="font-size:12px;font-weight:500;color:#999;">' + missing.join(', ') + '</div>';
    document.body.appendChild(toast);
    setTimeout(function(){ toast.remove(); }, 2500);
    return;
  }

  // 타입별 사이즈/수량 수집
  const adTypeDetails = {};
  Array.from(rqSelectedTypes).forEach(function(key) {
    var label = key.split('::')[1]||key;
    var safeLabel = label.replace(/[^a-zA-Z0-9가-힣]/g,'_');
    var detail = {};
    var wEl = document.getElementById('rq-w-'+safeLabel);
    var hEl = document.getElementById('rq-h-'+safeLabel);
    var qEl = document.getElementById('rq-qty-'+safeLabel);
    if(wEl && wEl.value) detail.w = wEl.value;
    if(hEl && hEl.value) detail.h = hEl.value;
    if(qEl && qEl.value) detail.qty = qEl.value;
    if(Object.keys(detail).length > 0) adTypeDetails[label] = detail;
  });

  // Build request object
  var deliveryDayLabel = '';
  if(has연출물) {
    if(deliveryDay === '별도지정일') {
      deliveryDayLabel = '별도 지정일 (퀵)' + (deliveryDate ? ' - '+deliveryDate : '');
    } else {
      deliveryDayLabel = deliveryDay + (deliveryDate ? ' ('+deliveryDate+')' : '');
    }
  }
  const request = {
    id: nextId(),
    submittedAt: new Date().toLocaleString('ko-KR'),
    status: '검토 중',
    dept, name, tel, branch,
    deliveryDay: deliveryDayLabel,
    title, deadline,
    adTypes: adTypesArr,
    adTypeDetails,
    bannerType: '', customSize: '',
    adTitle: document.getElementById('rq-ad-title').value.trim(),
    selling: document.getElementById('rq-selling').value.trim(),
    eventStart: '',
    eventEnd: '',
    eventDesc: document.getElementById('rq-event-desc').value.trim(),
    sitePhotos: rqSiteFiles.map(f=>({name:f.name, size:f.size})),
    refImages: rqRefFiles.map(f=>({name:f.name, size:f.size})),
  };

  // Save site photo previews (already loaded in DOM)
  const sitePrevWrap = document.getElementById('rq-site-preview');
  request.sitePhotoSrcs = sitePrevWrap ? Array.from(sitePrevWrap.querySelectorAll('img')).map(img=>img.src) : [];
  const refPrevWrap = document.getElementById('rq-ref-preview');
  request.refImageSrcs = refPrevWrap ? Array.from(refPrevWrap.querySelectorAll('img')).map(img=>img.src) : [];
  const prodPrevWrap = document.getElementById('rq-product-preview');
  request.productPhotoSrcs = prodPrevWrap ? Array.from(prodPrevWrap.querySelectorAll('img')).map(img=>img.src) : [];

  // 신청 번호 생성
  var today = new Date();
  var dateStr = today.getFullYear().toString()
    + String(today.getMonth()+1).padStart(2,'0')
    + String(today.getDate()).padStart(2,'0');
  var sameDayCount = (DB.requests||[]).filter(function(r){
    return r.reqCode && r.reqCode.indexOf('KD-'+dateStr) === 0;
  }).length;
  request.reqCode = 'KD-' + dateStr + '-' + String(sameDayCount+1).padStart(3,'0');

  if(!DB.requests) DB.requests = [];
  DB.requests.unshift(request);
  saveData();

  // Supabase에 저장
  sbSaveRequest(request).then(function(ok) {
    if(!ok) console.warn('Supabase 저장 실패');
  });

  modalClose('modalRequest');
  openRequestSuccess(request.reqCode);
}

// 신청서 수정 (검토 중 상태일 때만)
var rqEditTargetId = null;

function rqEditSave() {
  var dept = document.getElementById('rq-dept').value.trim();
  var name = document.getElementById('rq-name').value.trim();
  var tel  = document.getElementById('rq-tel').value.trim();
  var title = document.getElementById('rq-title').value.trim();
  var deadline = document.getElementById('rq-deadline').value;
  var adTitle = document.getElementById('rq-ad-title').value.trim();
  var selling = document.getElementById('rq-selling').value.trim();
  var eventDesc = document.getElementById('rq-event-desc').value.trim();

  var missing = [];
  if(!dept||!name||!tel) missing.push('요청자 정보');
  if(!title) missing.push('요청 제목');
  if(!deadline) missing.push('마감 요청일');
  if(missing.length > 0) {
    var toast = document.createElement('div');
    toast.style.cssText = 'position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);background:#fff;border:1.5px solid #e03333;color:#e03333;padding:20px 28px;border-radius:10px;font-size:14px;font-weight:700;z-index:9999;box-shadow:0 8px 32px rgba(0,0,0,0.15);text-align:center;line-height:1.6;';
    toast.innerHTML = '<div style="font-size:16px;margin-bottom:6px;">필수 항목을 작성해주세요</div><div style="font-size:12px;font-weight:500;color:#999;">'+missing.join(', ')+'</div>';
    document.body.appendChild(toast);
    setTimeout(function(){ toast.remove(); }, 2500);
    return;
  }

  // 광고 종류 + 사이즈 수집
  var adTypesArr = Array.from(rqSelectedTypes).map(function(k){ return k.split('::')[1]||k; });
  var adTypeDetails = {};
  Array.from(rqSelectedTypes).forEach(function(key) {
    var label = key.split('::')[1]||key;
    var safeLabel = label.replace(/\s/g,'_');
    var detail = {};
    var wEl = document.getElementById('rq-w-'+safeLabel);
    var hEl = document.getElementById('rq-h-'+safeLabel);
    var qEl = document.getElementById('rq-qty-'+safeLabel);
    if(wEl && wEl.value) detail.w = wEl.value;
    if(hEl && hEl.value) detail.h = hEl.value;
    if(qEl && qEl.value) detail.qty = qEl.value;
    if(Object.keys(detail).length > 0) adTypeDetails[label] = detail;
  });

  // 입고 관련
  var branch = (document.getElementById('rq-branch')?.value||'').trim();
  var deliveryDay = (document.getElementById('rq-delivery-day')?.value||'').trim();
  var deliveryDate = (document.getElementById('rq-delivery-date')?.value||'').trim();
  var deliveryDayLabel = deliveryDay;
  if(deliveryDate) deliveryDayLabel += ' (' + deliveryDate + ')';

  // idx 먼저 선언 (이후 사진 수집에서 기존 데이터 참조에 사용)
  var idx = (DB.requests||[]).findIndex(function(r){ return String(r.id)===String(rqEditTargetId); });
  if(idx===-1) return;

  // 현장 사진 수집 (DOM 미리보기에서)
  var sitePrevWrap = document.getElementById('rq-site-preview');
  var newSitePhotoSrcs = sitePrevWrap ? Array.from(sitePrevWrap.querySelectorAll('img')).map(function(img){ return img.src; }) : [];
  // 기존 사진 유지 + 새로 추가된 것 (빈 경우 기존 유지)
  var finalSitePhotoSrcs = newSitePhotoSrcs.length > 0 ? newSitePhotoSrcs : (DB.requests[idx].sitePhotoSrcs||[]);

  var refPrevWrap = document.getElementById('rq-ref-preview');
  var newRefImageSrcs = refPrevWrap ? Array.from(refPrevWrap.querySelectorAll('img')).map(function(img){ return img.src; }) : [];
  var finalRefImageSrcs = newRefImageSrcs.length > 0 ? newRefImageSrcs : (DB.requests[idx].refImageSrcs||[]);

  var prodPrevWrap = document.getElementById('rq-product-preview');
  var newProductPhotoSrcs = prodPrevWrap ? Array.from(prodPrevWrap.querySelectorAll('img')).map(function(img){ return img.src; }) : [];
  var finalProductPhotoSrcs = newProductPhotoSrcs.length > 0 ? newProductPhotoSrcs : (DB.requests[idx].productPhotoSrcs||[]);

  // Storage 업로드 후 저장
  processRequestFiles(finalSitePhotoSrcs, 'site_edit').then(async function(uploadedSite) {
    var uploadedRef = await processRequestFiles(finalRefImageSrcs, 'ref_edit');
    var uploadedProd = await processRequestFiles(finalProductPhotoSrcs, 'prod_edit');

    DB.requests[idx] = Object.assign({}, DB.requests[idx], {
      dept, name, tel, title, deadline, adTitle, selling, eventDesc,
      adTypes: adTypesArr, adTypeDetails, branch, deliveryDay: deliveryDayLabel,
      sitePhotoSrcs: uploadedSite, refImageSrcs: uploadedRef, productPhotoSrcs: uploadedProd
    });
    var updated = DB.requests[idx];
    saveData();

    sb.from('requests').update({
      dept:updated.dept, name:updated.name, tel:updated.tel,
      title:updated.title, deadline:updated.deadline,
      ad_title:updated.adTitle, selling:updated.selling, event_desc:updated.eventDesc,
      ad_types:updated.adTypes, ad_type_details:updated.adTypeDetails,
      branch:updated.branch, delivery_day:updated.deliveryDay,
      site_photo_srcs:updated.sitePhotoSrcs, ref_image_srcs:updated.refImageSrcs,
      product_photo_srcs:updated.productPhotoSrcs
    }).eq('id', updated.id).then(function(res){
      if(res.error) console.warn('수정 저장 실패:', res.error);
    });

    rqEditTargetId = null;
    modalClose('modalRequest');

    var toast2 = document.createElement('div');
    toast2.style.cssText = 'position:fixed;top:24px;left:50%;transform:translateX(-50%);background:#4a7cf4;color:#fff;padding:12px 28px;border-radius:50px;font-size:13px;font-weight:700;z-index:9999;';
    toast2.textContent = '✓ 신청 내용이 수정되었습니다';
    document.body.appendChild(toast2);
    setTimeout(function(){ toast2.remove(); }, 2500);
  });
}

function openReqEdit(reqId) {
  var req = (DB.requests||[]).find(function(r){ return String(r.id)===String(reqId); });
  if(!req) return;
  if(req.status !== '검토 중') return;
  rqEditTargetId = req.id;

  modalClose('modalReqStatus');
  openRequestModal();

  setTimeout(function() {
    // 기본 텍스트 필드 복원
    var set = function(id, val) { var el = document.getElementById(id); if(el) el.value = val||''; };
    set('rq-dept', req.dept);
    set('rq-name', req.name);
    set('rq-tel', req.tel);
    set('rq-title', req.title);
    set('rq-deadline', req.deadline);
    set('rq-ad-title', req.adTitle);
    set('rq-selling', req.selling);
    set('rq-event-desc', req.eventDesc);

    // 기존 현장 사진 미리보기 복원
    var spEl = document.getElementById('rq-site-preview');
    if(spEl && (req.sitePhotoSrcs||[]).length > 0) {
      spEl.innerHTML = (req.sitePhotoSrcs||[]).map(function(src, i) {
        return '<div style="position:relative;display:inline-block;">'
          + '<img src="'+src+'" data-existing="true" style="width:80px;height:80px;object-fit:cover;border-radius:6px;border:1px solid rgba(0,0,0,0.1);" />'
          + '</div>';
      }).join('');
    }

    // 기존 레퍼런스 이미지 복원
    var rpEl = document.getElementById('rq-ref-preview');
    if(rpEl && (req.refImageSrcs||[]).length > 0) {
      rpEl.innerHTML = (req.refImageSrcs||[]).map(function(src) {
        return '<div style="position:relative;display:inline-block;">'
          + '<img src="'+src+'" data-existing="true" style="width:80px;height:80px;object-fit:cover;border-radius:6px;border:1px solid rgba(0,0,0,0.1);" />'
          + '</div>';
      }).join('');
    }

    // 기존 상품 사진 복원
    var ppEl = document.getElementById('rq-product-preview');
    if(ppEl && (req.productPhotoSrcs||[]).length > 0) {
      ppEl.innerHTML = (req.productPhotoSrcs||[]).map(function(src) {
        return '<div style="position:relative;display:inline-block;">'
          + '<img src="'+src+'" data-existing="true" style="width:80px;height:80px;object-fit:cover;border-radius:6px;border:1px solid rgba(0,0,0,0.1);" />'
          + '</div>';
      }).join('');
    }

    // 광고 종류 복원
    (req.adTypes||[]).forEach(function(val) {
      var cat = ['A3 가로형','A4 세로형','와블러'].indexOf(val) !== -1 ? 'POP' : '연출물';
      rqSelectedTypes.add(cat+'::'+val);
      document.querySelectorAll('.rq-adcat-item').forEach(function(item) {
        if(item.dataset.val === val) item.classList.add('selected');
      });
    });

    renderAdTypeDetails();
    rqUpdateConditionalSections();

    setTimeout(function() {
      // 사이즈 복원
      var details = req.adTypeDetails || {};
      Object.keys(details).forEach(function(label) {
        var safe = label.replace(/\s/g,'_');
        var d = details[label];
        var w=document.getElementById('rq-w-'+safe); if(w&&d.w) w.value=d.w;
        var h=document.getElementById('rq-h-'+safe); if(h&&d.h) h.value=d.h;
        var q=document.getElementById('rq-qty-'+safe); if(q&&d.qty) q.value=d.qty;
      });
      // 입고 복원
      if(req.branch) { var b=document.getElementById('rq-branch'); if(b) b.value=req.branch; }
      if(req.deliveryDay) {
        var dateMatch = req.deliveryDay.match(/(\d{4}-\d{2}-\d{2})/);
        var isCustom = req.deliveryDay.indexOf('별도') !== -1;
        rqSwitchDeliveryTab(isCustom ? 'custom' : 'fixed');
        if(dateMatch) setTimeout(function(){ if(rqDeliveryPicker) rqDeliveryPicker.setDate(dateMatch[1]); }, 100);
      }
    }, 100);

    // 제출 버튼 텍스트
    var submitBtn = document.querySelector('#modalRequest .kbtn-confirm');
    if(submitBtn) submitBtn.textContent = '수정 저장';
  }, 150);
}

// ══════════════════════════════════════════════════════
//  AD REQUEST (기존 광고 기반 간략 신청)
// ══════════════════════════════════════════════════════
let adreqSiteFiles = [];
let adreqAdId = null;

function adreqSwitchDeliveryTab(mode) {
  var fixedBtn = document.getElementById('adreq-tab-fixed');
  var customBtn = document.getElementById('adreq-tab-custom');
  var fixedArea = document.getElementById('adreq-fixed-area');
  var customArea = document.getElementById('adreq-custom-area');
  if(!fixedBtn) return;
  if(mode === 'fixed') {
    fixedBtn.style.background = '#4a7cf4'; fixedBtn.style.color = '#fff'; fixedBtn.style.fontWeight = '700';
    customBtn.style.background = 'none'; customBtn.style.color = '#999'; customBtn.style.fontWeight = '600';
    fixedArea.style.display = ''; customArea.style.display = 'none';
    document.getElementById('adreq-delivery-day').value = '고정입고일';
  } else {
    customBtn.style.background = '#4a7cf4'; customBtn.style.color = '#fff'; customBtn.style.fontWeight = '700';
    fixedBtn.style.background = 'none'; fixedBtn.style.color = '#999'; fixedBtn.style.fontWeight = '600';
    customArea.style.display = ''; fixedArea.style.display = 'none';
    document.getElementById('adreq-delivery-day').value = '별도 지정일';
    setTimeout(adreqInitCustomCalendar, 50);
  }
}

function adreqInitFixedCalendar() {
  if(typeof flatpickr === 'undefined') return;
  var el = document.getElementById('adreq-fixed-calendar');
  if(!el || el._fp) return;
  el._fp = flatpickr(el, {
    locale: 'ko', dateFormat: 'Y-m-d',
    disable: [function(date){ return date.getDay()!==2 && date.getDay()!==5; }],
    onChange: function(sel, ds){ document.getElementById('adreq-delivery-date').value = ds; }
  });
}

function adreqInitCustomCalendar() {
  if(typeof flatpickr === 'undefined') return;
  var el = document.getElementById('adreq-custom-calendar');
  if(!el) return;
  if(el._fp) { el._fp.open(); return; }
  el._fp = flatpickr(el, {
    locale: 'ko', dateFormat: 'Y-m-d',
    onChange: function(sel, ds){ document.getElementById('adreq-custom-date').value = ds; }
  });
}

function openAdRequest(adId) {
  const ad = DB.ads.find(a => String(a.id) === String(adId));
  if(!ad) return;
  adreqAdId = adId;
  adreqSiteFiles = [];

  document.getElementById('adreq-cat').textContent = ad.mainCat + ' > ' + ad.subCat + ' > ' + ad.product;
  document.getElementById('adreq-title').textContent = ad.title;

  const thumb = (ad.types||[]).find(t=>t.src)?.src || '';
  const thumbEl = document.getElementById('adreq-thumb');
  thumbEl.innerHTML = thumb
    ? `<img src="${thumb}" style="width:100%;height:100%;object-fit:cover;" />`
    : `<svg viewBox="0 0 24 24" fill="none" stroke="#ccc" stroke-width="1.5" width="20" height="20"><rect x="3" y="7" width="18" height="13" rx="2"/><circle cx="9" cy="13" r="2"/><path d="m3 18 5-4 4 4 3-3 6 5"/></svg>`;

  var types = (ad.types||[]).filter(function(t){ return t.src; });
  var typeSelectEl = document.getElementById('adreq-type-select');
  var typeChecksEl = document.getElementById('adreq-type-checks');
  if(types.length > 1 && typeSelectEl && typeChecksEl) {
    typeSelectEl.style.display = '';
    typeChecksEl.innerHTML = types.map(function(t) {
      return '<label style="display:flex;align-items:center;gap:10px;padding:10px 12px;background:#fff;border-radius:6px;border:1.5px solid #e0e0e0;cursor:pointer;">'
        + '<input type="checkbox" name="adreq-type-check" value="'+t.name+'" checked style="width:16px;height:16px;cursor:pointer;" />'
        + '<img src="'+t.src+'" style="width:48px;height:36px;object-fit:cover;border-radius:4px;flex-shrink:0;" />'
        + '<span style="font-size:13px;font-weight:600;color:#111;">'+t.name+(t.subtitle?' · <span style="color:#888;font-weight:400;">'+t.subtitle+'</span>':'')+'</span>'
        + (t.width&&t.height ? '<span style="font-size:11px;color:#aaa;margin-left:auto;">'+t.width+'×'+t.height+'mm</span>' : '')
        + '</label>';
    }).join('');
  } else if(typeSelectEl) {
    typeSelectEl.style.display = 'none';
  }
  
  // 타입 탭 초기화
  document.querySelectorAll('.adreq-type-tab').forEach(t => t.classList.remove('active'));
  document.getElementById('adreq-woodlak-size').style.display = 'none';

  // 폼 초기화
  ['adreq-dept','adreq-name','adreq-tel','adreq-branch','adreq-deadline',
   'adreq-qty','adreq-desc','adreq-size-w','adreq-size-h',
   'adreq-delivery-date','adreq-custom-date','adreq-fixed-calendar','adreq-custom-calendar','adreq-other-text'].forEach(id => {
    const el = document.getElementById(id); if(el) el.value = '';
  });
  document.getElementById('adreq-site-preview').innerHTML = '';
  modalOpen('modalAdRequest');
  var _adreqScroll = document.getElementById('adreq-scroll-area');
  if(_adreqScroll) _adreqScroll.scrollTop = 0;
  adreqSwitchDeliveryTab('fixed');
  setTimeout(adreqInitFixedCalendar, 100);
  var dd = document.getElementById('adreq-delivery-date'); if(dd) dd.value='';
  var cd = document.getElementById('adreq-custom-date'); if(cd) cd.value='';
  var fc = document.getElementById('adreq-fixed-calendar'); if(fc) fc.value='';
  var cc = document.getElementById('adreq-custom-calendar'); if(cc) cc.value='';
}

function adreqSelectType(el) {
  document.querySelectorAll('.adreq-type-tab').forEach(t => t.classList.remove('active'));
  el.classList.add('active');
  const adType = el.dataset.type;
  const isWoodlak = adType === '우드락 셀링';
  const isOther = adType === '기타';
  document.getElementById('adreq-woodlak-size').style.display = isWoodlak ? '' : 'none';
  document.getElementById('adreq-other-input').style.display = isOther ? '' : 'none';
  if(!isWoodlak) {
    const w = document.getElementById('adreq-size-w');
    const h = document.getElementById('adreq-size-h');
    if(w) w.value = ''; if(h) h.value = '';
  }
  if(!isOther) {
    const ot = document.getElementById('adreq-other-text');
    if(ot) ot.value = '';
  }
}

function adreqHandlePhotos(input) {
  Array.from(input.files).forEach(file => {
    adreqSiteFiles.push(file);
    const reader = new FileReader();
    reader.onload = e => {
      const preview = document.getElementById('adreq-site-preview');
      const div = document.createElement('div');
      div.style.cssText = 'position:relative;width:72px;height:72px;border-radius:6px;overflow:hidden;border:1px solid rgba(0,0,0,0.1);flex-shrink:0;';
      div.innerHTML = `<img src="${e.target.result}" style="width:100%;height:100%;object-fit:cover;" />`;
      const del = document.createElement('button');
      del.innerHTML = '×';
      del.style.cssText = 'position:absolute;top:2px;right:2px;width:18px;height:18px;border-radius:50%;background:rgba(0,0,0,0.6);color:#fff;border:none;cursor:pointer;font-size:12px;line-height:1;display:flex;align-items:center;justify-content:center;';
      del.onclick = () => { adreqSiteFiles = adreqSiteFiles.filter(f=>f!==file); div.remove(); };
      div.appendChild(del);
      preview.appendChild(div);
    };
    reader.readAsDataURL(file);
  });
  input.value = '';
}

function adreqSubmit() {
  const dept     = (document.getElementById('adreq-dept')?.value||'').trim();
  const name     = (document.getElementById('adreq-name')?.value||'').trim();
  const tel      = (document.getElementById('adreq-tel')?.value||'').trim();
  const branch   = (document.getElementById('adreq-branch')?.value||'').trim();
  const deadline = (document.getElementById('adreq-deadline')?.value||'');
  const qty      = (document.getElementById('adreq-qty')?.value||'').trim();
  const desc     = (document.getElementById('adreq-desc')?.value||'').trim();
  const activeTab = document.querySelector('.adreq-type-tab.active');
  const adType   = activeTab?.dataset?.type || '';
  const sizeW    = (document.getElementById('adreq-size-w')?.value||'').trim();
  const sizeH    = (document.getElementById('adreq-size-h')?.value||'').trim();
  const ad = DB.ads.find(a => String(a.id) === String(adreqAdId));
  
  // 입고일 읽기
  const adreqDeliveryDay  = (document.getElementById('adreq-delivery-day')?.value||'').trim();
  const adreqDeliveryDate = (document.getElementById('adreq-delivery-date')?.value||'')
                         || (document.getElementById('adreq-custom-date')?.value||'');
  // 설치 위치 사진 필수 확인
  const sitePrevImgsCheck = Array.from((document.getElementById('adreq-site-preview')||{}).querySelectorAll?.('img')||[]);
  var checkedTypes = Array.from(document.querySelectorAll('input[name="adreq-type-check"]:checked')).map(function(el){ return el.value; });
  var selectedTypeStr = checkedTypes.length > 0 ? checkedTypes.join(', ') : '';

  var missing = [];
  if(!dept||!name||!tel) missing.push('요청자 정보');
  if(!deadline) missing.push('마감 요청일');
  if(!adreqDeliveryDate) missing.push('입고일');
  if(!adType) missing.push('광고물 형태');
  if(adType === '우드락 셀링' && (!sizeW || !sizeH)) missing.push('우드락 셀링 사이즈');
  if(!qty) missing.push('수량');
  if(sitePrevImgsCheck.length === 0) missing.push('설치 위치 사진');

  if(missing.length > 0) {
    var toast = document.createElement('div');
    toast.style.cssText = 'position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);background:#fff;border:1.5px solid #e03333;color:#e03333;padding:20px 28px;border-radius:10px;font-size:14px;font-weight:700;z-index:9999;box-shadow:0 8px 32px rgba(0,0,0,0.15);text-align:center;line-height:1.6;';
    toast.innerHTML = '<div style="font-size:16px;margin-bottom:6px;">필수 항목을 작성해주세요</div><div style="font-size:12px;font-weight:500;color:#999;">'+missing.join(', ')+'</div>';
    document.body.appendChild(toast); setTimeout(()=>toast.remove(), 2500); return;
  }

  const otherText = (document.getElementById('adreq-other-text')?.value||'').trim();
  const effectiveType = adType === '기타' ? (otherText ? `기타 (${otherText})` : '기타') : adType;
  const sizeText = adType === '우드락 셀링' ? `${effectiveType} (${sizeW}×${sizeH}mm)` : effectiveType;
  const sitePrevImgs = Array.from(document.getElementById('adreq-site-preview').querySelectorAll('img'));
  const sitePhotoSrcs = sitePrevImgs.map(img=>img.src);

  var today = new Date();
  var dateStr = today.getFullYear()+String(today.getMonth()+1).padStart(2,'0')+String(today.getDate()).padStart(2,'0');
  var cnt = (DB.requests||[]).filter(r=>r.reqCode&&r.reqCode.indexOf('KD-'+dateStr)===0).length;
  var reqCode = 'KD-'+dateStr+'-'+String(cnt+1).padStart(3,'0');

  var descLines = [
    `참고 광고: ${ad?.title||''}`,
    selectedTypeStr ? `선택 타입: ${selectedTypeStr}` : '',
    `광고물 형태: ${sizeText}`,
    qty ? `수량: ${qty}개` : '',
    branch ? `입고 지점: ${branch}` : '',
    adreqDeliveryDate ? `입고 요청일: ${adreqDeliveryDate} (${adreqDeliveryDay})` : '',
    desc ? `\n${desc}` : ''
  ].filter(Boolean).join('\n');

  var request = {
    id:nextId(), reqCode, submittedAt:new Date().toLocaleString('ko-KR'),
    status:'검토 중', dept, name, tel,
    title:`[${ad?.title||''}] ${sizeText}${qty?' · '+qty+'개':''}${branch?' · '+branch:''}`,
    deadline, adTypes:[adType],
    bannerType:'', customSize: adType==='우드락 셀링'?`${sizeW}×${sizeH}mm`:'',
    adTitle:ad?.title||'', selling:'',
    eventStart:'', eventEnd:'',
    eventDesc: descLines,
    branch, deliveryDay: adreqDeliveryDay, deliveryDate: adreqDeliveryDate,
    sitePhotoSrcs, refImageSrcs:[], manager:'', dueDate:''
  };
  if(!DB.requests) DB.requests=[];
  DB.requests.unshift(request);
  saveData();

  // 현장 사진 Storage 업로드 후 Supabase에 저장
  processRequestFiles(sitePhotoSrcs, 'adreq_site').then(function(uploadedSite) {
    request.sitePhotoSrcs = uploadedSite;
    // localStorage도 업데이트
    var idx = (DB.requests||[]).findIndex(function(r){ return r.id === request.id; });
    if(idx !== -1) { DB.requests[idx].sitePhotoSrcs = uploadedSite; saveData(); }
    sbSaveRequest(request).then(function(ok) {
      if(!ok) console.warn('Supabase 저장 실패 (adreq)');
    });
  });

  modalClose('modalAdRequest');
  openRequestSuccess(reqCode);
}

