function adminRenameSub(id, oldName) {
  var pill = document.querySelector('.ksub-pill[data-id="'+id+'"]');
  if(!pill) return;
  var input = document.createElement('input');
  input.value = oldName;
  input.style.cssText = 'width:'+(Math.max(60, oldName.length*14))+'px;padding:4px 10px;border:1.5px solid #111;border-radius:50px;font-size:14px;font-weight:600;font-family:Pretendard,sans-serif;outline:none;text-align:center;';
  pill.replaceWith(input);
  input.focus();
  input.select();
  async function save() {
    var newName = input.value.trim();
    if(!newName || newName === oldName) { renderAdmin(); return; }
    var idx = DB.subs.findIndex(function(s){ return s.id===id; });
    if(idx !== -1) {
      var mainCat = DB.subs[idx].mainCat;
      var affectedProductIds = [];
      DB.ads.forEach(function(a){ if(a.mainCat===mainCat && a.subCat===oldName) a.subCat=newName; });
      DB.products.forEach(function(p){ if(p.mainCat===mainCat && p.subCat===oldName) { p.subCat=newName; affectedProductIds.push(p.id); } });
      DB.subs[idx].name = newName;
      // Supabase await 저장
      await sb.from('subs').update({name:newName}).eq('id', id);
      if(affectedProductIds.length > 0) {
        await sb.from('products').update({sub_cat:newName}).in('id', affectedProductIds);
      }
      var adIds = DB.ads.filter(function(a){ return a.mainCat===mainCat && a.subCat===newName; }).map(function(a){ return a.id; });
      if(adIds.length > 0) {
        await sb.from('ads').update({sub_cat:newName}).in('id', adIds);
      }
      if(aState.sub === oldName) aState.sub = newName;
      saveData();
    }
    renderAdmin();
  }
  input.addEventListener('blur', save);
  input.addEventListener('keydown', function(e){ if(e.key==='Enter') { input.removeEventListener('blur', save); input.blur(); save(); } if(e.key==='Escape') { input.removeEventListener('blur', save); renderAdmin(); } });
}

function adminRenameProd(id, oldName) {
  var pill = document.querySelector('.kprod-btn[data-id="'+id+'"]');
  if(!pill) return;
  var input = document.createElement('input');
  input.value = oldName;
  input.style.cssText = 'width:'+(Math.max(60, oldName.length*14))+'px;padding:4px 10px;border:1.5px solid #111;border-radius:50px;font-size:13px;font-weight:600;font-family:Pretendard,sans-serif;outline:none;text-align:center;';
  pill.replaceWith(input);
  input.focus();
  input.select();
  async function save() {
    var newName = input.value.trim();
    if(!newName || newName === oldName) { renderAdmin(); return; }
    var idx = DB.products.findIndex(function(p){ return p.id===id; });
    if(idx !== -1) {
      DB.ads.forEach(function(a){ if(a.product===oldName) a.product=newName; });
      DB.products[idx].name = newName;
      // Supabase await 저장
      await sb.from('products').update({name:newName}).eq('id', id);
      // 관련 ads product도 Supabase 업데이트
      var adIds = DB.ads.filter(function(a){ return a.product===newName; }).map(function(a){ return a.id; });
      if(adIds.length > 0) {
        await sb.from('ads').update({product:newName}).in('id', adIds);
      }
      if(aState.prod === oldName) aState.prod = newName;
      saveData();
    }
    renderAdmin();
  }
  input.addEventListener('blur', save);
  input.addEventListener('keydown', function(e){ if(e.key==='Enter') { input.removeEventListener('blur', save); input.blur(); save(); } if(e.key==='Escape') { input.removeEventListener('blur', save); renderAdmin(); } });
}


