// catMgr 모달이 열려있는 동안 admin 뷰를 부분 갱신 (모달 닫지 않음)
function refreshAdminView() {
  // sub bar 갱신
  var subScroll = document.getElementById('adminSubScroll');
  if(subScroll) {
    var subs = getSubs(aState.cat);
    var html = '<button class="ksub-pill '+(aState.sub?'':'active')+'" onclick="adminSubSelect(\'\')">전체보기</button>';
    subs.forEach(function(s) {
      html += '<div style="display:flex;align-items:center;gap:2px;flex-shrink:0;">'
        + '<button class="ksub-pill '+(aState.sub===s.name?'active':'')+'" data-id="'+s.id+'" onclick="adminSubSelect(\''+s.name+'\')">'+s.name+'</button>'
        + '<button class="ksub-pill-del" title="'+s.name+' 삭제" onclick="adminDeleteSub('+s.id+',\''+s.name+'\')">×</button>'
        + '</div>';
    });
    subScroll.innerHTML = html;
  }
  // prod bar 갱신
  if(typeof renderAdminProdRow === 'function') renderAdminProdRow();
  // content 갱신
  renderAdminContent();
}


var catMgrCat = '';
var catMgrSub = '';

function openCatMgr() {
  catMgrCat = aState.cat || MAIN_CATS[0];
  catMgrSub = '';

  // 대분류 탭 렌더
  var tabsEl = document.getElementById('catmgr-cattabs');
  if(tabsEl) {
    tabsEl.style.display = 'grid';
    tabsEl.style.gridTemplateColumns = 'repeat('+MAIN_CATS.length+',1fr)';
    tabsEl.innerHTML = MAIN_CATS.map(function(c) {
      return '<button onclick="catMgrSelectCat(\''+c+'\')" id="catmgr-tab-'+c+'" style="padding:10px 4px;background:none;border:none;border-bottom:2px solid transparent;font-size:14px;font-weight:600;color:#aaa;cursor:pointer;font-family:Pretendard,sans-serif;white-space:nowrap;margin-bottom:-1px;text-align:center;transition:all .15s;">'+c+'</button>';
    }).join('');
  }

  // 버튼 이벤트 바인딩
  var subAddBtn = document.getElementById('catmgr-sub-add-btn');
  if(subAddBtn) { subAddBtn.onclick = function(){ catMgrToggleSubInput(); }; }

  var subConfirm = document.getElementById('catmgr-sub-add-confirm');
  if(subConfirm) { subConfirm.onclick = function(){ catMgrAddSub(); }; }

  var subInput = document.getElementById('catmgr-sub-input');
  if(subInput) {
    subInput.onkeydown = function(e) {
      if(e.key === 'Enter') catMgrAddSub();
      if(e.key === 'Escape') catMgrToggleSubInput();
    };
  }

  var prodAddBtn = document.getElementById('catmgr-prod-add-btn');
  if(prodAddBtn) { prodAddBtn.onclick = function(){ catMgrToggleProdInput(); }; }

  var prodConfirm = document.getElementById('catmgr-prod-add-confirm');
  if(prodConfirm) { prodConfirm.onclick = function(){ catMgrAddProd(); }; }

  var prodInput = document.getElementById('catmgr-prod-input');
  if(prodInput) {
    prodInput.onkeydown = function(e) {
      if(e.key === 'Enter') catMgrAddProd();
      if(e.key === 'Escape') catMgrToggleProdInput();
    };
  }

  modalOpen('modalCatMgr');
  catMgrSelectCat(catMgrCat);
}

function catMgrSelectCat(cat) {
  catMgrCat = cat;
  catMgrSub = '';
  // 탭 활성화
  MAIN_CATS.forEach(function(c) {
    var t = document.getElementById('catmgr-tab-'+c);
    if(t) {
      t.style.color = c===cat ? '#111' : '#aaa';
      t.style.borderBottomColor = c===cat ? '#111' : 'transparent';
      t.style.fontWeight = c===cat ? '800' : '600';
    }
  });
  catMgrRenderSubs();
  catMgrRenderProds();
}

function catMgrToggleSubInput() {
  var row = document.getElementById('catmgr-sub-input-row');
  var isHidden = row.style.display === 'none';
  row.style.display = isHidden ? '' : 'none';
  if(isHidden) setTimeout(function(){ document.getElementById('catmgr-sub-input').focus(); }, 50);
}

function catMgrToggleProdInput() {
  var row = document.getElementById('catmgr-prod-input-row');
  var isHidden = row.style.display === 'none';
  row.style.display = isHidden ? '' : 'none';
  if(isHidden) setTimeout(function(){ document.getElementById('catmgr-prod-input').focus(); }, 50);
}

function catMgrRenderSubs() {
  var list = document.getElementById('catmgr-sub-list');
  var subs = getSubs(catMgrCat);
  if(subs.length === 0) {
    list.innerHTML = '<div style="font-size:13px;color:#ccc;text-align:center;padding:16px 0;">등록된 세부 카테고리가 없습니다</div>';
    return;
  }
  list.innerHTML = '';
  subs.forEach(function(s) {
    var isSelected = s.name === catMgrSub;
    var row = document.createElement('div');
    row.id = 'catmgr-sub-row-' + s.id;
    row.style.cssText = 'display:flex;align-items:center;gap:8px;padding:14px 16px;border-radius:8px;cursor:pointer;transition:background .15s,border .15s;'
      + (isSelected ? 'background:#111;border:1.5px solid #111;' : 'background:#fff;border:1.5px solid rgba(0,0,0,0.1);');
    var nameSpan = document.createElement('span');
    nameSpan.id = 'catmgr-sub-name-' + s.id;
    nameSpan.textContent = s.name;
    nameSpan.style.cssText = 'flex:1;font-size:15px;font-weight:700;letter-spacing:-0.02em;color:'+(isSelected?'#fff':'#111')+';';
    var renameBtn = document.createElement('button');
    renameBtn.id = 'catmgr-sub-rename-' + s.id;
    renameBtn.textContent = '수정';
    renameBtn.style.cssText = 'padding:5px 14px;background:'+(isSelected?'rgba(255,255,255,0.15)':'#f2f2f2')+';border:none;border-radius:7px;font-size:12px;font-weight:600;cursor:pointer;font-family:Pretendard,sans-serif;color:'+(isSelected?'#fff':'#555')+';';
    var deleteBtn = document.createElement('button');
    deleteBtn.textContent = '삭제';
    deleteBtn.style.cssText = 'padding:5px 14px;background:#e03333;border:none;border-radius:7px;font-size:12px;font-weight:700;cursor:pointer;font-family:Pretendard,sans-serif;color:#fff;';
    renameBtn.addEventListener('click', function(e){ e.stopPropagation(); catMgrRenameSub(s.id, s.name); });
    deleteBtn.addEventListener('click', function(e){ e.stopPropagation(); catMgrDeleteSub(s.id, s.name); });
    row.addEventListener('click', function(){ catMgrSelectSub(s.name); });

    // 세부 카테고리 행을 드롭 타겟으로 - 상품을 드래그해서 이동 가능
    row.addEventListener('dragover', function(e){
      e.preventDefault();
      row.style.background = s.name === catMgrSub ? '#333' : '#e8f0fe';
      row.style.borderColor = '#4a7cf4';
    });
    row.addEventListener('dragleave', function(){
      row.style.background = s.name === catMgrSub ? '#111' : '#fff';
      row.style.borderColor = s.name === catMgrSub ? '#111' : 'rgba(0,0,0,0.1)';
    });
    row.addEventListener('drop', function(e){
      e.preventDefault();
      row.style.background = s.name === catMgrSub ? '#111' : '#fff';
      row.style.borderColor = s.name === catMgrSub ? '#111' : 'rgba(0,0,0,0.1)';
      var prodId = parseInt(e.dataTransfer.getData('prodId'));
      if(!isNaN(prodId)) {
        catMgrSelectSub(s.name);
        catMgrMoveProd(prodId, s.name);
      }
    });

    row.appendChild(nameSpan); row.appendChild(renameBtn); row.appendChild(deleteBtn);
    list.appendChild(row);
  });
}

function catMgrSelectSub(sub) {
  catMgrSub = sub === catMgrSub ? '' : sub;
  var subs = getSubs(catMgrCat);
  subs.forEach(function(s) {
    var row = document.getElementById('catmgr-sub-row-' + s.id);
    var nameSpan = document.getElementById('catmgr-sub-name-' + s.id);
    var renameBtn = document.getElementById('catmgr-sub-rename-' + s.id);
    if(!row || !nameSpan) return;
    var isSel = s.name === catMgrSub;
    row.style.background = isSel ? '#111' : '#fff';
    row.style.border = isSel ? '1.5px solid #111' : '1.5px solid rgba(0,0,0,0.1)';
    nameSpan.style.color = isSel ? '#fff' : '#111';
    if(renameBtn) { renameBtn.style.background = isSel ? 'rgba(255,255,255,0.15)' : '#f2f2f2'; renameBtn.style.color = isSel ? '#fff' : '#555'; }
  });
  catMgrRenderProds();
}

function catMgrRenderProds() {
  var labelEl = document.getElementById('catmgr-prod-sub-label');
  var addBtn = document.getElementById('catmgr-prod-add-btn');
  var inputRow = document.getElementById('catmgr-prod-input-row');
  var list = document.getElementById('catmgr-prod-list');
  if(!catMgrSub) {
    if(labelEl) labelEl.textContent = '';
    if(addBtn) addBtn.style.display='none';
    if(inputRow) inputRow.style.display='none';
    list.innerHTML = '<div style="font-size:13px;color:#ccc;text-align:center;padding:20px 0;">세부 카테고리를 선택하면 상품 목록이 표시됩니다</div>';
    return;
  }
  if(labelEl) labelEl.textContent = catMgrCat + ' › ' + catMgrSub;
  if(addBtn) addBtn.style.display='flex';
  var prods = getProds(catMgrCat, catMgrSub);
  list.innerHTML = '';
  if(prods.length === 0) {
    list.innerHTML = '<div style="font-size:13px;color:#ccc;text-align:center;padding:16px 0;">등록된 상품이 없습니다</div>';
    // 드롭 타겟 (빈 상태)
    list.addEventListener('dragover', function(e){ e.preventDefault(); list.style.background='#f0f4ff'; });
    list.addEventListener('dragleave', function(){ list.style.background=''; });
    list.addEventListener('drop', function(e){
      e.preventDefault(); list.style.background='';
      var prodId = parseInt(e.dataTransfer.getData('prodId'));
      catMgrMoveProd(prodId, catMgrSub);
    });
    return;
  }
  prods.forEach(function(p) {
    var row = document.createElement('div');
    row.id = 'catmgr-prod-row-' + p.id;
    row.draggable = true;
    row.style.cssText = 'display:flex;align-items:center;gap:8px;padding:12px 14px;border-radius:8px;background:#fff;border:1.5px solid rgba(0,0,0,0.1);cursor:grab;';

    // 드래그 핸들 아이콘
    var handle = document.createElement('span');
    handle.innerHTML = '<svg viewBox="0 0 24 24" fill="none" stroke="#ccc" stroke-width="2" width="14" height="14"><circle cx="9" cy="6" r="1.5" fill="#ccc"/><circle cx="15" cy="6" r="1.5" fill="#ccc"/><circle cx="9" cy="12" r="1.5" fill="#ccc"/><circle cx="15" cy="12" r="1.5" fill="#ccc"/><circle cx="9" cy="18" r="1.5" fill="#ccc"/><circle cx="15" cy="18" r="1.5" fill="#ccc"/></svg>';
    handle.style.cssText = 'flex-shrink:0;display:flex;align-items:center;';

    var nameSpan = document.createElement('span');
    nameSpan.id = 'catmgr-prod-name-' + p.id;
    nameSpan.textContent = p.name;
    nameSpan.style.cssText = 'flex:1;font-size:15px;font-weight:700;letter-spacing:-0.02em;color:#111;';

    // 이동 버튼
    var moveBtn = document.createElement('button');
    moveBtn.textContent = '이동';
    moveBtn.title = '다른 세부 카테고리로 이동';
    moveBtn.style.cssText = 'padding:5px 12px;background:#f0f4ff;color:#4a7cf4;border:1px solid #c5d5ff;border-radius:7px;font-size:12px;font-weight:600;cursor:pointer;font-family:Pretendard,sans-serif;';

    var renameBtn = document.createElement('button');
    renameBtn.id = 'catmgr-prod-rename-' + p.id;
    renameBtn.textContent = '수정';
    renameBtn.style.cssText = 'padding:5px 12px;background:#f2f2f2;border:none;border-radius:7px;font-size:12px;font-weight:600;cursor:pointer;font-family:Pretendard,sans-serif;color:#555;';

    var deleteBtn = document.createElement('button');
    deleteBtn.textContent = '삭제';
    deleteBtn.style.cssText = 'padding:5px 12px;background:#e03333;border:none;border-radius:7px;font-size:12px;font-weight:700;cursor:pointer;font-family:Pretendard,sans-serif;color:#fff;';

    // 드래그 이벤트
    row.addEventListener('dragstart', function(e){
      e.dataTransfer.setData('prodId', p.id);
      row.style.opacity = '0.4';
    });
    row.addEventListener('dragend', function(){
      row.style.opacity = '1';
    });
    row.addEventListener('dragover', function(e){
      e.preventDefault();
      row.style.borderColor = '#4a7cf4';
    });
    row.addEventListener('dragleave', function(){
      row.style.borderColor = 'rgba(0,0,0,0.1)';
    });
    row.addEventListener('drop', function(e){
      e.preventDefault();
      row.style.borderColor = 'rgba(0,0,0,0.1)';
      var draggedId = parseInt(e.dataTransfer.getData('prodId'));
      if(draggedId === p.id) return;
      catMgrMoveProd(draggedId, catMgrSub);
    });

    moveBtn.addEventListener('click', function(){ catMgrShowMoveDialog(p.id, p.name); });
    renameBtn.addEventListener('click', function(){ catMgrRenameProd(p.id, p.name); });
    deleteBtn.addEventListener('click', function(){ catMgrDeleteProd(p.id, p.name); });

    row.appendChild(handle);
    row.appendChild(nameSpan);
    row.appendChild(moveBtn);
    row.appendChild(renameBtn);
    row.appendChild(deleteBtn);
    list.appendChild(row);
  });

  // 리스트 전체도 드롭 타겟
  list.addEventListener('dragover', function(e){ e.preventDefault(); });
  list.addEventListener('drop', function(e){
    e.preventDefault();
    var prodId = parseInt(e.dataTransfer.getData('prodId'));
    catMgrMoveProd(prodId, catMgrSub);
  });
}

// 상품을 다른 세부 카테고리로 이동 (드롭)
function catMgrMoveProd(prodId, targetSub) {
  var prod = DB.products.find(function(p){ return p.id === prodId; });
  if(!prod || prod.subCat === targetSub) return;
  prod.subCat = targetSub;
  sbUpdateProd(prod);
  saveData();
  catMgrRenderProds();
  refreshAdminView();
}

// 이동 다이얼로그 (버튼 클릭)
function catMgrShowMoveDialog(prodId, prodName) {
  var existing = document.getElementById('catmgr-move-dialog');
  if(existing) existing.remove();

  var subs = getSubs(catMgrCat).filter(function(s){ return s.name !== catMgrSub; });

  var dialog = document.createElement('div');
  dialog.id = 'catmgr-move-dialog';
  dialog.style.cssText = 'position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,0.45);display:flex;align-items:center;justify-content:center;padding:20px;';
  var box = document.createElement('div');
  box.style.cssText = 'background:#fff;border-radius:12px;padding:24px;width:100%;max-width:360px;font-family:Pretendard,sans-serif;';

  var subsHTML = subs.length > 0
    ? '<div style="font-size:12px;font-weight:700;color:#aaa;margin:14px 0 8px;letter-spacing:0.02em;">다른 세부 카테고리로 이동</div>'
      + '<div style="display:flex;flex-direction:column;gap:6px;">'
      + subs.map(function(s){
          return '<button onclick="catMgrMoveProd(' + prodId + ',\'' + s.name + '\');document.getElementById(\'catmgr-move-dialog\').remove();" '
            + 'style="padding:12px 16px;background:#f2f2f2;border:none;border-radius:8px;font-size:14px;font-weight:600;cursor:pointer;font-family:Pretendard,sans-serif;text-align:left;color:#111;">' + s.name + '</button>';
        }).join('')
      + '</div>'
    : '<div style="font-size:12px;font-weight:700;color:#aaa;margin:14px 0 8px;">이동할 다른 세부 카테고리가 없습니다</div>';

  box.innerHTML = '<div style="font-size:16px;font-weight:800;margin-bottom:4px;color:#111;">이동</div>'
    + '<div style="font-size:13px;color:#888;margin-bottom:4px;">' + prodName + '</div>'
    + '<div style="border-top:1px solid #f2f2f2;padding-top:14px;margin-top:10px;">'
    + '<div style="font-size:12px;font-weight:700;color:#aaa;margin-bottom:8px;letter-spacing:0.02em;">세부 카테고리로 승격</div>'
    + '<button id="catmgr-convert-btn" style="width:100%;padding:12px 16px;background:#fff3cd;border:1.5px solid #ffc107;border-radius:8px;font-size:14px;font-weight:600;cursor:pointer;font-family:Pretendard,sans-serif;text-align:left;color:#856404;">⬆ ' + prodName + ' → 세부 카테고리로 변환</button>'
    + subsHTML
    + '</div>'
    + '<button onclick="document.getElementById(\'catmgr-move-dialog\').remove();" style="margin-top:14px;width:100%;padding:11px;background:none;border:1.5px solid #d8dce3;border-radius:8px;font-size:14px;font-weight:600;cursor:pointer;font-family:Pretendard,sans-serif;color:#888;">취소</button>';

  dialog.appendChild(box);
  dialog.addEventListener('click', function(e){ if(e.target===dialog) dialog.remove(); });
  document.body.appendChild(dialog);

  // 승격 버튼 이벤트
  document.getElementById('catmgr-convert-btn').addEventListener('click', function(){
    dialog.remove();
    catMgrConvertToSub(prodId, prodName);
  });
}

// 상품을 세부 카테고리로 변환
function catMgrConvertToSub(prodId, prodName) {
  if(!confirm('\'' + prodName + '\' 을 세부 카테고리로 승격하시겠습니까?\n상품 목록에서 제거되고 세부 카테고리로 추가됩니다.')) return;
  var prod = DB.products.find(function(p){ return p.id === prodId; });
  if(!prod) return;
  DB.products = DB.products.filter(function(p){ return p.id !== prodId; });
  var newSub = {id: nextId(), mainCat: prod.mainCat, name: prod.name};
  DB.subs.push(newSub);
  saveData();
  sbConvertProdToSub(prod);
  catMgrRenderSubs();
  catMgrRenderProds();
  refreshAdminView();
}

function catMgrAddSub() {
  var input = document.getElementById('catmgr-sub-input');
  var name = (input ? input.value : '').trim();
  if(!name) return;
  if(DB.subs.find(function(s){ return s.mainCat===catMgrCat && s.name===name; })) { alert('이미 존재합니다'); return; }
  var newSub = {id:nextId(), mainCat:catMgrCat, name:name};
  DB.subs.push(newSub);
  saveData(); sbSaveSub(newSub);
  input.value = '';
  document.getElementById('catmgr-sub-input-row').style.display = 'none';
  catMgrRenderSubs();
  refreshAdminView();
}

function catMgrAddProd() {
  var input = document.getElementById('catmgr-prod-input');
  var name = (input ? input.value : '').trim();
  if(!name || !catMgrSub) return;
  if(DB.products.find(function(p){ return p.mainCat===catMgrCat && p.subCat===catMgrSub && p.name===name; })) { alert('이미 존재합니다'); return; }
  var newProd = {id:nextId(), mainCat:catMgrCat, subCat:catMgrSub, name:name};
  DB.products.push(newProd);
  saveData(); sbSaveProd(newProd);
  input.value = '';
  document.getElementById('catmgr-prod-input-row').style.display = 'none';
  catMgrRenderProds();
  refreshAdminView();
}

function catMgrRenameSub(id, oldName) {
  var row = document.getElementById('catmgr-sub-row-' + id);
  var nameSpan = document.getElementById('catmgr-sub-name-' + id);
  var renameBtn = document.getElementById('catmgr-sub-rename-' + id);
  if(!row || !nameSpan || !renameBtn) return;
  var input = document.createElement('input');
  input.className = 'kinput'; input.value = oldName;
  input.style.cssText = 'flex:1;font-size:14px;padding:6px 10px;';
  nameSpan.replaceWith(input);
  renameBtn.textContent = '저장';
  input.focus(); input.select();

  async function doSave() {
    var newName = input.value.trim();
    if(!newName || newName===oldName) { catMgrRenderSubs(); return; }

    // 버튼 비활성화로 중복 저장 방지
    renameBtn.disabled = true;
    renameBtn.textContent = '저장 중...';

    var idx = DB.subs.findIndex(function(s){ return s.id===id; });
    if(idx !== -1) {
      var affectedProductIds = [];
      DB.ads.forEach(function(a){ if(a.subCat===oldName && a.mainCat===catMgrCat) a.subCat=newName; });
      DB.products.forEach(function(p){ if(p.subCat===oldName && p.mainCat===catMgrCat) { p.subCat=newName; affectedProductIds.push(p.id); } });
      DB.subs[idx].name = newName;

      // Supabase에 순차적으로 await 저장 (완료 보장)
      await sb.from('subs').update({name:newName}).eq('id', id);
      if(affectedProductIds.length > 0) {
        await sb.from('products').update({sub_cat:newName}).in('id', affectedProductIds);
      }
      // 관련 ads sub_cat도 Supabase 업데이트
      var adIds = DB.ads.filter(function(a){ return a.subCat===newName && a.mainCat===catMgrCat; }).map(function(a){ return a.id; });
      if(adIds.length > 0) {
        await sb.from('ads').update({sub_cat:newName}).in('id', adIds);
      }

      saveData(); // 모든 Supabase 저장 완료 후 localStorage 동기화
    }
    if(catMgrSub===oldName) catMgrSub=newName;
    if(aState.sub===oldName) aState.sub=newName;
    catMgrRenderSubs(); catMgrRenderProds(); refreshAdminView();
  }

  renameBtn.onclick = doSave;
  input.addEventListener('keydown', function(e){ if(e.key==='Enter') doSave(); if(e.key==='Escape') catMgrRenderSubs(); });
}

function catMgrRenameProd(id, oldName) {
  var row = document.getElementById('catmgr-prod-row-' + id);
  var nameSpan = document.getElementById('catmgr-prod-name-' + id);
  var renameBtn = document.getElementById('catmgr-prod-rename-' + id);
  if(!row || !nameSpan || !renameBtn) return;
  var input = document.createElement('input');
  input.className = 'kinput'; input.value = oldName;
  input.style.cssText = 'flex:1;font-size:14px;padding:6px 10px;';
  nameSpan.replaceWith(input);
  renameBtn.textContent = '저장';
  input.focus(); input.select();

  async function doSave() {
    var newName = input.value.trim();
    if(!newName || newName===oldName) { catMgrRenderProds(); return; }

    renameBtn.disabled = true;
    renameBtn.textContent = '저장 중...';

    var idx = DB.products.findIndex(function(p){ return p.id===id; });
    if(idx !== -1) {
      DB.ads.forEach(function(a){ if(a.product===oldName && a.subCat===catMgrSub && a.mainCat===catMgrCat) a.product=newName; });
      DB.products[idx].name = newName;

      // Supabase await 저장
      await sb.from('products').update({name:newName}).eq('id', id);
      // 관련 ads product도 Supabase 업데이트
      var adIds = DB.ads.filter(function(a){ return a.product===newName && a.subCat===catMgrSub && a.mainCat===catMgrCat; }).map(function(a){ return a.id; });
      if(adIds.length > 0) {
        await sb.from('ads').update({product:newName}).in('id', adIds);
      }

      if(aState.prod === oldName) aState.prod = newName;
      saveData();
    }
    catMgrRenderProds();
    refreshAdminView();
  }

  renameBtn.onclick = doSave;
  input.addEventListener('keydown', function(e){ if(e.key==='Enter') doSave(); if(e.key==='Escape') catMgrRenderProds(); });
}

function catMgrDeleteSub(id, name) {
  var list = document.getElementById('catmgr-sub-list');
  var targetRow = null;
  list.querySelectorAll('div').forEach(function(r) {
    if(r.querySelector && r.querySelector('span') && r.querySelector('span').textContent===name) targetRow=r;
  });
  if(!targetRow) return;
  targetRow.style.background = '#fff0f0';
  targetRow.style.border = '1.5px solid #e03333';
  targetRow.innerHTML =
    '<span style="flex:1;font-size:13px;font-weight:600;color:#e03333;">\''+name+'\' 삭제할까요?</span>'
    +'<button id="catdel-confirm-'+id+'" style="padding:5px 16px;background:#e03333;border:none;border-radius:7px;font-size:12px;font-weight:700;cursor:pointer;color:#fff;font-family:Pretendard,sans-serif;">삭제</button>'
    +'<button id="catdel-cancel-'+id+'" style="padding:5px 16px;background:#f2f2f2;border:none;border-radius:7px;font-size:12px;font-weight:600;cursor:pointer;color:#555;font-family:Pretendard,sans-serif;">취소</button>';
  document.getElementById('catdel-confirm-'+id).addEventListener('click', function() {
    DB.ads = DB.ads.filter(function(a){ return !(a.mainCat===catMgrCat && a.subCat===name); });
    DB.products = DB.products.filter(function(p){ return !(p.mainCat===catMgrCat && p.subCat===name); });
    DB.subs = DB.subs.filter(function(s){ return s.id!==id; });
    saveData(); sbDeleteSub(id);
    if(catMgrSub===name) catMgrSub='';
    catMgrRenderSubs(); catMgrRenderProds(); refreshAdminView();
  });
  document.getElementById('catdel-cancel-'+id).addEventListener('click', function() { catMgrRenderSubs(); });
}

function catMgrDeleteProd(id, name) {
  var list = document.getElementById('catmgr-prod-list');
  var targetRow = null;
  list.querySelectorAll('div').forEach(function(r) {
    if(r.querySelector && r.querySelector('span') && r.querySelector('span').textContent===name) targetRow=r;
  });
  if(!targetRow) return;
  targetRow.style.background = '#fff0f0';
  targetRow.style.border = '1.5px solid #e03333';
  targetRow.innerHTML =
    '<span style="flex:1;font-size:13px;font-weight:600;color:#e03333;">\''+name+'\' 삭제할까요?</span>'
    +'<button id="proddel-confirm-'+id+'" style="padding:5px 16px;background:#e03333;border:none;border-radius:7px;font-size:12px;font-weight:700;cursor:pointer;color:#fff;font-family:Pretendard,sans-serif;">삭제</button>'
    +'<button id="proddel-cancel-'+id+'" style="padding:5px 16px;background:#f2f2f2;border:none;border-radius:7px;font-size:12px;font-weight:600;cursor:pointer;color:#555;font-family:Pretendard,sans-serif;">취소</button>';
  document.getElementById('proddel-confirm-'+id).addEventListener('click', function() {
    DB.ads = DB.ads.filter(function(a){ return !(a.product===name && a.subCat===catMgrSub && a.mainCat===catMgrCat); });
    DB.products = DB.products.filter(function(p){ return p.id!==id; });
    saveData(); sbDeleteProd(id);
    catMgrRenderProds(); refreshAdminView();
  });
  document.getElementById('proddel-cancel-'+id).addEventListener('click', function() { catMgrRenderProds(); });
}

// ── Category Edit Modal ──
var editCatMode = ''; // 'sub' or 'prod'

function openEditCatModal(mode) {
  editCatMode = mode;
  var title = document.getElementById('editCatTitle');
  var desc = document.getElementById('editCatDesc');
  var input = document.getElementById('editCatNewInput');
  input.value = '';

  if(mode === 'sub') {
    title.textContent = '세부 카테고리 편집';
    desc.textContent = aState.cat + ' · 세부 카테고리를 관리하세요';
  } else {
    title.textContent = '상품 카테고리 편집';
    desc.textContent = aState.cat + ' > ' + aState.sub + ' · 상품을 관리하세요';
  }
  renderEditCatList();
  modalOpen('modalEditCat');
}

function renderEditCatList() {
  var list = document.getElementById('editCatList');
  var items = editCatMode === 'sub'
    ? getSubs(aState.cat)
    : getProds(aState.cat, aState.sub);

  if(items.length === 0) {
    list.innerHTML = '<div style="text-align:center;padding:20px;font-size:13px;color:#bbb;">등록된 항목이 없습니다</div>';
    return;
  }

  list.innerHTML = '';
  items.forEach(function(item) {
    var row = document.createElement('div');
    row.className = 'kedit-item';
    row.id = 'kedit-row-' + item.id;
    row.innerHTML =
      '<span class="kedit-item-name" id="kedit-name-'+item.id+'">'+item.name+'</span>'
      + '<button class="kedit-item-btn kedit-rename-btn" data-id="'+item.id+'" data-name="'+item.name.replace(/"/g,'&quot;')+'">수정</button>'
      + '<button class="kedit-item-btn kedit-del-btn" data-id="'+item.id+'" data-name="'+item.name.replace(/"/g,'&quot;')+'">삭제</button>';
    row.querySelector('.kedit-rename-btn').addEventListener('click', function(){ editCatStartRename(item.id, item.name); });
    row.querySelector('.kedit-del-btn').addEventListener('click', function(){ editCatDelete(item.id, item.name); });
    list.appendChild(row);
  });
}

function editCatStartRename(id, oldName) {
  var nameEl = document.getElementById('kedit-name-'+id);
  if(!nameEl) return;
  var input = document.createElement('input');
  input.value = oldName;
  nameEl.replaceWith(input);
  input.focus(); input.select();

  var saveBtn = document.querySelector('#kedit-row-'+id+' .kedit-rename-btn');
  if(saveBtn) { saveBtn.textContent = '저장'; saveBtn.className = 'kedit-item-btn kedit-rename-btn saving'; saveBtn.onclick = function(){ doRename(); }; }

  function doRename() {
    var newName = input.value.trim();
    if(!newName) return;
    if(newName === oldName) { renderEditCatList(); return; }
    if(editCatMode === 'sub') {
      var idx = DB.subs.findIndex(function(s){ return s.id==id; });
      if(idx !== -1) {
        DB.ads.forEach(function(a){ if(a.subCat===oldName) a.subCat=newName; });
        DB.products.forEach(function(p){ if(p.subCat===oldName) p.subCat=newName; });
        DB.subs[idx].name = newName;
        saveData();
        sb.from('subs').update({name:newName}).eq('id',id);
      }
    } else {
      var idx2 = DB.products.findIndex(function(p){ return p.id==id; });
      if(idx2 !== -1) {
        DB.ads.forEach(function(a){ if(a.product===oldName) a.product=newName; });
        DB.products[idx2].name = newName;
        saveData();
        sb.from('products').update({name:newName}).eq('id',id);
      }
    }
    renderEditCatList();
    renderAdminSubRow();
    renderAdminProdRow();
  }
  input.addEventListener('keydown', function(e){ if(e.key==='Enter') doRename(); if(e.key==='Escape') renderEditCatList(); });
}

function editCatDelete(id, name) {
  var row = document.getElementById('kedit-row-'+id);
  if(!row) return;
  row.innerHTML =
    '<span style="flex:1;font-size:12px;color:#e03333;font-weight:600;">\''+name+'\' 삭제할까요?</span>'
    +'<button id="editdel-confirm-'+id+'" style="padding:4px 12px;background:#e03333;border:none;border-radius:6px;font-size:11px;font-weight:700;cursor:pointer;color:#fff;font-family:Pretendard,sans-serif;">삭제</button>'
    +'<button id="editdel-cancel-'+id+'" style="padding:4px 12px;background:#e8e8e8;border:none;border-radius:6px;font-size:11px;font-weight:600;cursor:pointer;color:#555;font-family:Pretendard,sans-serif;">취소</button>';
  document.getElementById('editdel-confirm-'+id).addEventListener('click', function() {
    if(editCatMode === 'sub') {
      DB.ads = DB.ads.filter(function(a){ return !(a.mainCat===aState.cat && a.subCat===name); });
      DB.products = DB.products.filter(function(p){ return !(p.mainCat===aState.cat && p.subCat===name); });
      DB.subs = DB.subs.filter(function(s){ return s.id!==id; });
      saveData(); sbDeleteSub(id);
      if(aState.sub===name) aState.sub='';
    } else {
      DB.ads = DB.ads.filter(function(a){ return !(a.mainCat===aState.cat && a.subCat===aState.sub && a.product===name); });
      DB.products = DB.products.filter(function(p){ return p.id!==id; });
      saveData(); sbDeleteProd(id);
      if(aState.prod===name) aState.prod='__all__';
    }
    renderEditCatList();
    renderAdmin();
  });
  document.getElementById('editdel-cancel-'+id).addEventListener('click', function() {
    renderEditCatList();
  });
}

function editCatAdd() {
  var input = document.getElementById('editCatNewInput');
  var name = input.value.trim();
  if(!name) return;
  if(editCatMode === 'sub') {
    if(DB.subs.find(function(s){ return s.mainCat===aState.cat && s.name===name; })) { alert('이미 존재하는 카테고리입니다'); return; }
    var newSub = {id:nextId(), mainCat:aState.cat, name:name};
    DB.subs.push(newSub);
    saveData();
    sbSaveSub(newSub);
  } else {
    if(!aState.sub) { alert('세부 카테고리를 먼저 선택하세요'); return; }
    if(DB.products.find(function(p){ return p.mainCat===aState.cat && p.subCat===aState.sub && p.name===name; })) { alert('이미 존재하는 상품입니다'); return; }
    var newProd = {id:nextId(), mainCat:aState.cat, subCat:aState.sub, name:name};
    DB.products.push(newProd);
    saveData();
    sbSaveProd(newProd);
  }
  input.value = '';
  setTimeout(renderEditCatList, 100);
  renderAdmin();
}

