  var badge = cnt > 0 ? '<span style="background:#e03333;color:#fff;font-size:10px;font-weight:700;border-radius:50px;padding:2px 7px;line-height:1.4;margin-left:6px;">'+cnt+'</span>' : '';
  return '<button class="ktab-btn'+(isArchive?' active':'')+'" onclick="adminTab=\'archive\';renderAdmin();">'
