function openReqStatusModal() {
  document.getElementById('statusCodeInput').value = '';
  document.getElementById('statusResult').innerHTML = '';
  modalOpen('modalReqStatus');
  setTimeout(function(){ document.getElementById('statusCodeInput').focus(); }, 200);
}

function openReqUserDetail(reqId) {
  var req = (DB.requests||[]).find(function(r){ return String(r.id)===String(reqId); });
  if(!req) return;
  var statusColors = {'검토 중':'#F97316','진행 중':'#3B82F6','완료':'#1C6B3A','반려':'#EF4444'};
  var sc = statusColors[req.status]||'#111';

  // 광고 종류 + 사이즈
  var adTypePills = (req.adTypes||[]).map(function(t){
    var d = (req.adTypeDetails||{})[t];
    var dStr = '';
    if(d){ if(d.w&&d.h) dStr+=' '+d.w+'×'+d.h+'mm'; if(d.qty) dStr+=' ×'+d.qty+'개'; }
    return '<span style="background:#4a7cf4;color:#fff;font-size:12px;font-weight:600;padding:4px 12px;border-radius:50px;display:inline-block;margin:2px;">'+t+dStr+'</span>';
  }).join('');

  var rows = [
    ['소속', req.dept], ['이름', req.name], ['연락처', req.tel],
    ['마감 요청일', req.deadline], ['입고 지점', req.branch], ['입고 요청일', req.deliveryDay],
    ['타이틀', req.adTitle], ['셀링 문구', req.selling], ['행사 내용', req.eventDesc]
  ].filter(function(r){ return r[1]; }).map(function(r){
    return '<div style="margin-bottom:10px;"><div style="font-size:10px;font-weight:700;color:#aaa;margin-bottom:3px;text-transform:uppercase;">'+r[0]+'</div>'
      +'<div style="font-size:14px;color:#111;white-space:pre-wrap;line-height:1.5;">'+r[1]+'</div></div>';
  }).join('');

  // 사진 미리보기
  var sitePics = (req.sitePhotoSrcs||[]).map(function(src){
    return '<img src="'+src+'" onclick="openLightbox(\''+src+'\')" style="width:80px;height:80px;object-fit:cover;border-radius:6px;cursor:zoom-in;border:1px solid rgba(0,0,0,0.08);" />';
  }).join('');

  var html = '<div style="padding:0;">'
    +'<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px;">'
      +'<span style="background:'+sc+';color:#fff;font-size:12px;font-weight:700;padding:4px 12px;border-radius:50px;">'+req.status+'</span>'
      +'<span style="font-size:11px;color:#aaa;font-weight:600;">'+( req.reqCode||'')+'</span>'
    +'</div>'
    +'<div style="font-size:18px;font-weight:900;letter-spacing:-0.03em;margin-bottom:4px;">'+req.title+'</div>'
    +'<div style="font-size:12px;color:#bbb;margin-bottom:20px;">신청: '+req.submittedAt+'</div>'
    + (adTypePills ? '<div style="margin-bottom:16px;"><div style="font-size:10px;font-weight:700;color:#aaa;margin-bottom:6px;text-transform:uppercase;">광고 종류</div><div>'+adTypePills+'</div></div>' : '')
    +'<div style="background:#f8faff;border:1px solid #e2e8ff;border-radius:6px;padding:16px;margin-bottom:16px;">'+rows+'</div>'
    + (sitePics ? '<div style="margin-bottom:16px;"><div style="font-size:10px;font-weight:700;color:#aaa;margin-bottom:8px;text-transform:uppercase;">현장 사진</div><div style="display:flex;flex-wrap:wrap;gap:8px;">'+sitePics+'</div></div>' : '')
    +'<button onclick="this.closest(\'.kmodal-overlay\').classList.remove(\'open\')" style="width:100%;padding:13px;background:#4a7cf4;color:#fff;border:none;border-radius:50px;font-size:14px;font-weight:700;cursor:pointer;font-family:Pretendard,sans-serif;">닫기</button>'
  +'</div>';

  // 팝업 모달 동적 생성
  var overlay = document.getElementById('modalReqUserDetail');
  if(!overlay) {
    overlay = document.createElement('div');
    overlay.id = 'modalReqUserDetail';
    overlay.className = 'kmodal-overlay center';
    overlay.innerHTML = '<div class="kmodal-sheet" style="max-width:480px;border-radius:12px;max-height:90vh;overflow-y:auto;"><div class="kmodal-handle"></div><span class="kmodal-swipe-hint">아래로 내려서 닫기</span><div id="modalReqUserDetailContent"></div></div>';
    overlay.addEventListener('click', function(e){ if(e.target===overlay) overlay.classList.remove('open'); });
    document.body.appendChild(overlay);
  }
  document.getElementById('modalReqUserDetailContent').innerHTML = html;
  overlay.scrollTop=0; const _s=overlay.querySelector('.kmodal-sheet'); if(_s)_s.scrollTop=0; overlay.classList.add('open');
}

function searchReqStatus() {
  var tel = document.getElementById('statusCodeInput').value.trim().replace(/[^0-9]/g,'');
  var result = document.getElementById('statusResult');
  if(!tel || tel.length < 9) {
    result.innerHTML = '<div style="color:#e03333;font-size:13px;text-align:center;padding:12px 0;">연락처를 정확히 입력해주세요</div>';
    return;
  }
  result.innerHTML = '<div style="text-align:center;padding:20px 0;font-size:13px;color:#aaa;">조회 중...</div>';
  // Supabase에서 직접 조회
  sb.from('requests').select('*').order('id', {ascending:false}).then(function(res) {
    if(!res.error && res.data) DB.requests = res.data.map(function(r){ return {
      id:r.id, reqCode:r.req_code, submittedAt:r.submitted_at, status:r.status,
      dept:r.dept, name:r.name, tel:r.tel, title:r.title, deadline:r.deadline,
      adTypes:r.ad_types||[], bannerType:r.banner_type, customSize:r.custom_size,
      adTitle:r.ad_title, selling:r.selling, eventStart:r.event_start, eventEnd:r.event_end,
      eventDesc:r.event_desc, sitePhotoSrcs:r.site_photo_srcs||[], refImageSrcs:r.ref_image_srcs||[],
      manager:r.manager, dueDate:r.due_date,
      branch:r.branch||'', deliveryDay:r.delivery_day||'',
      adTypeDetails:r.ad_type_details||{}, productPhotoSrcs:r.product_photo_srcs||[]
    }; });
    var matched = (DB.requests||[]).filter(function(r){
      return r.tel && r.tel.replace(/[^0-9]/g,'') === tel;
    });
  if(matched.length === 0) {
    result.innerHTML = '<div style="text-align:center;padding:28px 0;">'
      + '<svg viewBox="0 0 48 48" fill="none" stroke="#ccc" stroke-width="1.5" width="36" height="36" style="margin:0 auto 12px;display:block;"><circle cx="24" cy="24" r="20"/><path d="M24 14v12M24 32v2"/></svg>'
      + '<div style="font-size:15px;font-weight:600;color:#555;margin-bottom:6px;">신청 내역을 찾을 수 없습니다</div>'
      + '<div style="font-size:13px;color:#bbb;">입력한 연락처로 등록된 신청이 없습니다</div></div>';
    return;
  }
  var statusColors = {'검토 중':'#F97316','진행 중':'#3B82F6','완료':'#1C6B3A','반려':'#EF4444'};
  var cards = matched.map(function(req) {
    var sc = statusColors[req.status]||'#111';
    var editBtn = '';
    var statusNote = '';
    var detailBtn = '<button onclick="openReqUserDetail(\''+req.id+'\')" style="flex:1;padding:10px;background:#f8faff;border:1px solid #e2e8ff;border-radius:6px;font-size:13px;font-weight:600;color:#555;cursor:pointer;font-family:Pretendard,sans-serif;">📋 신청 내용 보기</button>';
    if(req.status === '검토 중') {
      editBtn = '<button onclick="openReqEdit(\''+req.id+'\')" style="flex:1;padding:10px;background:#4a7cf4;border:none;border-radius:6px;font-size:13px;font-weight:700;color:#fff;cursor:pointer;font-family:Pretendard,sans-serif;">✎ 수정</button>';
    } else if(req.status === '진행 중') {
      statusNote = '<div style="margin-top:10px;background:#eff6ff;border-radius:6px;padding:10px 12px;font-size:12px;color:#1d4ed8;line-height:1.6;">진행 중인 신청은 수정할 수 없습니다.<br>변경이 필요하면 담당자 <strong>'+(req.manager||'')+'</strong>에게 문의해주세요.</div>';
    } else if(req.status === '반려') {
      statusNote = '<div style="margin-top:10px;background:#fff0f0;border-radius:6px;padding:10px 12px;font-size:12px;color:#e03333;">반려 처리되었습니다. 담당자에게 문의해주세요.</div>';
    } else if(req.status === '완료') {
      statusNote = '<div style="margin-top:10px;background:#edfaed;border-radius:6px;padding:10px 12px;font-size:12px;color:#2d7a2d;">작업이 완료되었습니다.</div>';
    }
    return '<div style="border:1.5px solid rgba(0,0,0,0.08);border-radius:10px;overflow:hidden;margin-bottom:10px;">'
      + '<div style="background:#f4f6ff;padding:12px 16px;display:flex;align-items:center;justify-content:space-between;border-bottom:1px solid rgba(0,0,0,0.06);">'
        + '<div style="font-size:11px;font-weight:700;color:#999;letter-spacing:1px;">'+(req.reqCode||'번호 없음')+'</div>'
        + '<span style="background:'+sc+';color:#fff;font-size:11px;font-weight:700;padding:3px 10px;border-radius:50px;">'+req.status+'</span>'
      + '</div>'
      + '<div style="padding:14px 16px;">'
        + '<div style="font-size:15px;font-weight:800;color:#111;margin-bottom:4px;letter-spacing:-0.02em;">'+(req.title||'제목 없음')+'</div>'
        + '<div style="font-size:12px;color:#999;margin-bottom:12px;">'+(req.name||'')+(req.dept?' · '+req.dept:'')+'</div>'
        + '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:10px;">'
          + '<div style="background:#f4f6ff;border-radius:6px;padding:10px 12px;"><div style="font-size:10px;color:#999;font-weight:600;margin-bottom:3px;">담당자</div><div style="font-size:13px;font-weight:600;color:#111;">'+(req.manager||'미지정')+'</div></div>'
          + '<div style="background:#f4f6ff;border-radius:6px;padding:10px 12px;"><div style="font-size:10px;color:#999;font-weight:600;margin-bottom:3px;">완료 예정일</div><div style="font-size:13px;font-weight:600;color:#111;">'+(req.dueDate||'미정')+'</div></div>'
        + '</div>'
        + '<div style="font-size:12px;color:#bbb;">마감: '+(req.deadline||'미정')+' · 신청: '+req.submittedAt+'</div>'
        + statusNote
        + '<div style="display:flex;gap:8px;margin-top:10px;">' + detailBtn + editBtn + '</div>'
      + '</div>'
    + '</div>';
  }).join('');

    result.innerHTML = '<div style="font-size:13px;font-weight:600;color:#999;margin-bottom:12px;">총 '+matched.length+'건의 신청 내역</div>' + cards;
  });
}



