function openRequestSuccess(code) {
  document.getElementById('successReqCode').textContent = code;
  modalOpen('modalReqSuccess');
}

function copyReqCode() {
  var code = document.getElementById('successReqCode').textContent;
  var btn = document.getElementById('copyReqBtn');
  navigator.clipboard.writeText(code).then(function(){
    btn.textContent = '✓ 복사됨';
    btn.style.borderColor = '#111';
    btn.style.color = '#111';
    setTimeout(function(){ btn.textContent = '복사하기'; btn.style.borderColor = '#ddd'; btn.style.color = '#555'; }, 2000);
  }).catch(function(){
    // fallback
    var el = document.createElement('textarea');
    el.value = code;
    document.body.appendChild(el);
    el.select();
    document.execCommand('copy');
    document.body.removeChild(el);
    btn.textContent = '✓ 복사됨';
    setTimeout(function(){ btn.textContent = '복사하기'; }, 2000);
  });
}


